scwin.f_getParametrSetting = async function () {
  var kcomcd = scwin.p_kcomcd;
  var blno = scwin.p_blno;
  var type = scwin.p_type;
  var mblno = scwin.p_mblno;
  scwin.linkType = type;
  if ($c.str.trim($p, scwin.linkType) == "HawbCreate") {
    if (mblno == "null" || mblno == "") {
      return false;
    }
    scwin.f_Create();
    scwin.hd_kcomcd = kcomcd;
    ed_mblno.setValue(mblno);
    await scwin.f_MasterConsolNoLoading();
    if (scwin.actionFlag == "Create") {
      await scwin.f_RetrieveMasterInfo(); // 마스터에서 정보 뿌려줌
    }
    ed_blno.focus();
  } else if ($c.str.trim($p, scwin.linkType) == "ColoadHawbCreate") {
    if (mblno == "null" || mblno == "") {
      return false;
    }
    scwin.f_Create();
    scwin.hd_kcomcd = kcomcd;
    ed_mblno.setValue(mblno);
    await scwin.f_MasterConsolNoLoading();
    if (scwin.actionFlag == "Create") {
      await scwin.f_RetrieveMasterBookinInfo(); // 마스터 부킹에서 정보 뿌려줌
    }
    ed_blno.focus();
  } else if ($c.str.trim($p, scwin.linkType) == "HawbRetrieve") {
    if (blno == "null" || blno == "") {
      return false;
    }
    scwin.hd_kcomcd = kcomcd;
    ed_blno.setValue(blno);
    await scwin.f_MhnoLoading();
    await scwin.f_Retrieve();
  } else {
    if (blno == "null" || blno == "") {
      return false;
    }
    scwin.hd_kcomcd = kcomcd;
    ed_blno.setValue(blno);
    await scwin.f_MhnoLoading();
    await scwin.f_Retrieve();
  }
};

