scwin.f_ProcessResult = async function (gubun) {
  switch (gubun) {
    case "None":
      await scwin.f_Set("INIT");
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003); // 해당 되는 자료가 없습니다.
      ed_blno.focus();
      break;
    case "HouseInfo":
      await scwin.f_Set("RETRIEVE");
      scwin.f_SettingValue();
      await scwin.f_MhnoLoading();
      await scwin.f_InvoiceCheck_All("B"); // 운임 발생시 ITEM, Department 수정 못 하게 하기 위해 검색
      break;
    case "NotExistMasterBookingInfo":
      scwin.processFlag = "None";
      ed_mblno.setValue("");
      break;
    case "ExistMasterBookingInfo":
      scwin.processFlag = "ExistMasterBookingInfo";
      scwin.f_MasterBookingListBinding("Retrieve", ds_MasterBookingInfo, ds_HouseBillInfo);
      break;
    default:
      break;
  }
};

