scwin.f_RetrieveCustomerBookingResult = async function (gubun) {
  switch (gubun) {
    case "None":
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003); // 해당 되는 자료가 없습니다.
      scwin.ed_srno = "";
      break;
    case "BookingInfo":
      var ds = ds_CustomerBookingInfo;
      var row = ds.getRowPosition();
      if ($c.str.trim($p, ds.getCellData(row, "blno")) != "") {
        await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_003, [ds.getCellData(row, "blno")]); // 이미 존재하는 House B/L No : @ 가 있습니다.";
        scwin.ed_srno = "";
        return false;
      }
      scwin.ed_srno = ds.getCellData(row, "srno");
      ed_shcd.setValue(ds.getCellData(row, "shcd"));
      if ($c.str.trim($p, ed_shcd.getValue()) != "") {
        scwin.f_PopUp("Shipper", "T", "F", "F");
      }
      ed_cncd.setValue(ds.getCellData(row, "cncd"));
      if ($c.str.trim($p, ed_cncd.getValue()) != "") {
        scwin.f_PopUp("Consignee", "T", "F", "F");
      }
      ed_nocd.setValue(ds.getCellData(row, "pncd"));
      txt_nonm.setValue("");
      if ($c.str.trim($p, ed_nocd.getValue()) != "") {
        scwin.f_PopUp("Partner", "T", "F", "F");
      }
      ed_ascd.setValue(ds.getCellData(row, "ascd"));
      txt_asnm.setValue("");
      if ($c.str.trim($p, ed_ascd.getValue()) != "") {
        scwin.f_PopUp("Customer", "T", "F", "F");
      }
      ed_sacd.setValue(ds.getCellData(row, "sacd"));
      txt_sanm.setValue(ds.getCellData(row, "sanm"));
      ed_itcd.setValue(ds.getCellData(row, "itcd"));
      txt_itnm.setValue(ds.getCellData(row, "itnm"));

      //2020.03.02 국제영업3팀 개선사항 : 부킹에 등록된 ITEM 없을 경우 자동으로 30000000 (일반화물) 으로 기입 처리
      if (txt_itnm.getValue() == "") {
        ed_itcd.setValue("30000000");
        txt_itnm.setValue("일반화물");
      }
      if ($c.str.trim($p, ed_ascd.getValue()) != "") {
        await scwin.f_departmentInfo();
      }

      // Booking 번호 검색 후 복사 실행
      if (scwin.processFlag == "Copy") {
        ds_HouseBillInfo.modifyRowStatus(ds_HouseBillInfo.getRowPosition(), "C");
        ds_HouseLicenseInfo.modifyRowStatus(ds_HouseLicenseInfo.getRowPosition(), "C");
        await scwin.f_Save();
        scwin.processFlag = "None";
      }

      //기본으로 등록자 ID 기입 처리
      ed_blpic.setValue(scwin.userId);
      txt_blpic.setValue("");
      scwin.f_PopUp("B/L PIC", "T");
      break;
    default:
      break;
  }
};

