scwin.f_InvoiceCheck_All = async function (gbun) {
  var ds = ds_InvoiceCheckParam;
  ds.removeAll();
  ds.insertRow();
  var row = ds.getRowPosition() || 0;
  ds.setCellData(row, "odrNo", ds_HouseBillInfo.getCellData(ds_HouseBillInfo.getRowPosition() || 0, "odrNo")); // Order No
  ds.setCellData(row, "mblHblCls", "H");
  ds.setCellData(row, "kcomcd", scwin.hd_kcomcd); // 법인코드
  ds.setCellData(row, "seaAirCls", "A"); // 해운/항공 구분
  ds.setCellData(row, "blNo", $c.str.trim($p, ed_blno.getValue())); // Master Bill No
  ds.setCellData(row, "mhno", $c.str.trim($p, lc_hmhno.getValue())); // Consol No
  ds.setCellData(row, "gbun", gbun == "B" ? "B" : "F"); // b/l 운임 구분 ('B','F')

  scwin.spMsg = "";
  scwin.spRtn = "-1";
  let e = await $c.sbm.execute($p, sbm_InvoiceCheck);
  if (e.responseJSON.resultDataSet[0].Code < 0) {
    return;
  } else {
    var r = ds_InvoiceCheck.getRowPosition() || 0;
    scwin.spMsg = ds_InvoiceCheck.getCellData(r, "spMsg");
    scwin.spRtn = ds_InvoiceCheck.getCellData(r, "spRtn");
    scwin.freightYn = scwin.spRtn;
  }
};

//-------------------------------------------------------------------------
// 조회조건 바인딩
//-------------------------------------------------------------------------
scwin.f_ProcessBinding = function (ds, gubun) {
  var isMap = typeof ds.set === "function";
  var reset = function () {
    if (isMap) {
      ds.setEmptyValue();
    } else {
      ds.removeAll();
      ds.insertRow();
    }
  };
  var setVal = function (key, val) {
    if (isMap) {
      ds.set(key, val);
    } else {
      ds.setCellData(ds.getRowPosition(), key, val);
    }
  };
  switch (gubun) {
    case "HouseBillSearch":
      // dma_HouseBillSearch
      reset();
      setVal("kcomcd", scwin.hd_kcomcd || "DBEX");
      setVal("blno", $c.str.trim($p, ed_blno.getValue()));
      setVal("mhno", lc_hmhno.getValue());
      setVal("iogb", scwin.hd_iogb);
      break;
    case "HouseBillSave":
      setVal("kcomcd", scwin.hd_kcomcd || "DBEX");
      setVal("iogb", scwin.hd_iogb);
      setVal("blno", $c.str.trim($p, ed_blno.getValue()));
      setVal("mhno", lc_hmhno.getValue());
      break;
    case "HouseLicenseSave":
      setVal("kcomcd", scwin.hd_kcomcd || "DBEX");
      setVal("blno", $c.str.trim($p, ed_blno.getValue()));
      setVal("mhno", lc_hmhno.getValue());
      break;
    case "CustomerBookingSearch":
      reset();
      setVal("kcomcd", scwin.hd_kcomcd || "DBEX");
      setVal("srno", $c.str.trim($p, scwin.ed_srno));
      setVal("iogb", scwin.hd_iogb);
      break;
    case "HouseBillCheck":
      reset();
      setVal("kcomcd", scwin.hd_kcomcd);
      setVal("blno", $c.str.trim($p, ed_blno.getValue()));
      setVal("iogb", scwin.hd_iogb);
      break;
    case "RetrieveMasterInfo":
      reset();
      setVal("kcomcd", scwin.hd_kcomcd);
      setVal("iogb", scwin.hd_iogb);
      setVal("blno", $c.str.trim($p, ed_mblno.getValue()));
      break;
    case "MasterBillSearch":
      reset();
      setVal("kcomcd", scwin.hd_kcomcd);
      setVal("blno", $c.str.trim($p, ed_mblno.getValue()));
      setVal("mhno", lc_hmhno.getValue());
      setVal("iogb", scwin.hd_iogb);
      break;
    default:
      break;
  }
};

