scwin.f_Copy = async function () {
  var ok = await $c.win.confirm($p, scwin.MSG_LO_WRN_001); //해당 B/L 번호로 복사 하시겠습니까?
  if (!ok) return;
  scwin.actionFlag = "Copy";
  scwin.f_DefaultValue("Copy");
  await scwin.f_Set("CREATE");
  ds_SellingFreightInfo_tmp.removeAll();
  ds_PartnerFreightInfo_tmp.removeAll();
  ds_BuyingFreightInfo_tmp.removeAll();
  ds_SellingFreightInfo_tmp.setJSON(ds_SellingFreightInfo_freight.getAllJSON());
  ds_PartnerFreightInfo_tmp.setJSON(ds_PartnerFreightInfo_freight.getAllJSON());
  ds_BuyingFreightInfo_tmp.setJSON(ds_BuyingFreightInfo_freight.getAllJSON());
  scwin.f_Create_freight();
  ds_SellingFreightInfo_freight.setJSON(ds_SellingFreightInfo_tmp.getAllJSON());
  ds_PartnerFreightInfo_freight.setJSON(ds_PartnerFreightInfo_tmp.getAllJSON());
  ds_BuyingFreightInfo_freight.setJSON(ds_BuyingFreightInfo_tmp.getAllJSON());
  for (var i = 0; i < ds_SellingFreightInfo_freight.getTotalRow(); i++) {
    ds_SellingFreightInfo_freight.setCellData(i, "blNo", "");
    ds_SellingFreightInfo_freight.setCellData(i, "certiNo", "");
    ds_SellingFreightInfo_freight.setCellData(i, "odrNo", "");
    ds_SellingFreightInfo_freight.setCellData(i, "mhno", "NONE");
    ds_SellingFreightInfo_freight.setCellData(i, "prtnGrpNo", "");
    ds_SellingFreightInfo_freight.setCellData(i, "rsltsStdDt", scwin.strCurDate);
    ds_SellingFreightInfo_freight.modifyRowStatus(i, "C"); // insert 로 변경.

    // tobe 추가 (AllCopy시 CURR 컬럼 값이 0으로 세팅됨)
    ds_SellingFreightInfo_freight.setCellData(i, "crcCd", "0");
    scwin.setGridColumnReadonly("Selling", i);
  }
  for (var i = 0; i < ds_PartnerFreightInfo_freight.getTotalRow(); i++) {
    ds_PartnerFreightInfo_freight.setCellData(i, "blNo", "");
    ds_PartnerFreightInfo_freight.setCellData(i, "certiNo", "");
    ds_PartnerFreightInfo_freight.setCellData(i, "odrNo", "");
    ds_PartnerFreightInfo_freight.setCellData(i, "mhno", "NONE");
    ds_PartnerFreightInfo_freight.setCellData(i, "prtnGrpNo", "");
    ds_PartnerFreightInfo_freight.setCellData(i, "rsltsStdDt", scwin.strCurDate);
    ds_PartnerFreightInfo_freight.modifyRowStatus(i, "C"); // insert 로 변경.

    // tobe 추가 (AllCopy시 CURR 컬럼 값이 0으로 세팅됨)
    ds_PartnerFreightInfo_freight.setCellData(i, "crcCd", "0");
    scwin.setGridColumnReadonly("Partner", i);
  }
  for (var i = 0; i < ds_BuyingFreightInfo_freight.getTotalRow(); i++) {
    ds_BuyingFreightInfo_freight.setCellData(i, "blNo", "");
    ds_BuyingFreightInfo_freight.setCellData(i, "pchsCertiNo", "");
    ds_BuyingFreightInfo_freight.setCellData(i, "odrNo", "");
    ds_BuyingFreightInfo_freight.setCellData(i, "mhno", "NONE");
    ds_BuyingFreightInfo_freight.setCellData(i, "prtnGrpNo", "");
    ds_BuyingFreightInfo_freight.setCellData(i, "rsltsStdDt", scwin.strCurDate);
    ds_BuyingFreightInfo_freight.modifyRowStatus(i, "C"); // insert 로 변경.

    // tobe 추가 (AllCopy시 CURR 컬럼 값이 0으로 세팅됨)
    ds_BuyingFreightInfo_freight.setCellData(i, "crcCd", "0");
    scwin.setGridColumnReadonly("Buying", i);
  }
  ds_SellingFreightInfo_freight.setRowPosition(0);
  ds_PartnerFreightInfo_freight.setRowPosition(0);
  ds_BuyingFreightInfo_freight.setRowPosition(0);

  //COPY Consignee -> Customer 복사 기능 추가
  //order no 초기화
  ed_odrNo.setValue("");
  ed_cjdt.setValue("");
  txt_ngnm1.setValue("");
  txt_ngnm2.setValue("");
  txt_ngnm3.setValue("");
  txt_ngnm4.setValue("");
  ed_ediwht.setValue("");
  if ($c.str.trim($p, ed_cncd.getValue()) != "") {
    ed_ascd.setValue($c.str.trim($p, ed_cncd.getValue()));
    txt_asnm.setValue($c.str.trim($p, scwin.txt_cnnm1));
  } else if ($c.str.trim($p, ed_ntcd.getValue()) != "") {
    ed_ascd.setValue($c.str.trim($p, ed_ntcd.getValue()));
    txt_asnm.setValue($c.str.trim($p, scwin.txt_ntnm1));
  }

  // B/L PIC값이 없을때 등록자 아이디로 입력(PIC값이 null되는걸 방지)
  if (ed_blpic.getValue() == "") {
    ed_blpic.setValue(scwin.userId);
    scwin.f_PopUp("B/L PIC", "T");
  }
};

