      scwin._openMenu("Export Customer Booking", "/ui/il/airout/aobk/ar_101_01_01b.xml", "ar_101_01_01b.xml", {
        kcomcd: commonParam.kcomcd,
        srno: $c.str.trim($p, scwin.ed_srno)
      });
      break;
