        dsHouse.setCellData(rowH, "ontime", dsBooking.getCellData(rowB, "ontime"));
        dsHouse.setCellData(rowH, "fltno", fltno);
        dsHouse.setCellData(rowH, "ptcd1", fltno.substring(0, 2));
        dsHouse.setCellData(rowH, "agcd", dsBooking.getCellData(rowB, "cocd"));
        dsHouse.setCellData(rowH, "agnm", dsBooking.getCellData(rowB, "conm"));
        dsHouse.setCellData(rowH, "dpcd", dsBooking.getCellData(rowB, "dpcd"));
        dsHouse.setCellData(rowH, "dstn", dsBooking.getCellData(rowB, "dscd"));
        dsHouse.setCellData(rowH, "dpnm", dsBooking.getCellData(rowB, "dpnm"));
        dsHouse.setCellData(rowH, "dscd1", dsBooking.getCellData(rowB, "dscd"));
        dsHouse.setCellData(rowH, "dsnm1", dsBooking.getCellData(rowB, "dsnm"));
        dsHouse.setCellData(rowH, "mftpkg", dsBooking.getCellData(rowB, "ctn"));
        dsHouse.setCellData(rowH, "mftwht", dsBooking.getCellData(rowB, "gwht"));
        dsHouse.setCellData(rowH, "avdt", dsBooking.getCellData(rowB, "avdt"));
        dsHouse.setCellData(rowH, "avtime", dsBooking.getCellData(rowB, "avtime"));
        dsHouse.setCellData(rowH, "lrgb", dsBooking.getCellData(rowB, "srgb"));
        scwin.f_DestinationCheck();
        if ($c.str.trim($p, scwin.ed_ctcd).length > 0) {
          scwin.f_OpenCommonPopUp("Country", "T", "F", "F");
        }
