scwin.f_FreightTypeGetting = function () {
  chb_frpc1.setValue("0");
  chb_frpc2.setValue("0");
  chb_otpc1.setValue("0");
  chb_otpc2.setValue("0");

  //WT/VAL
  if (scwin.hd_frpc == "PP") {
    chb_frpc1.setValue("1");
  }
  if (scwin.hd_frpc == "CC") {
    chb_frpc2.setValue("1");
  }
  if (scwin.hd_frpc == "PC") {
    chb_frpc1.setValue("1");
    chb_frpc2.setValue("1");
  }

  //OTHER
  if (scwin.hd_otpc == "PP") {
    chb_otpc1.setValue("1");
  }
  if (scwin.hd_otpc == "CC") {
    chb_otpc2.setValue("1");
  }
  if (scwin.hd_otpc == "PC") {
    chb_otpc1.setValue("1");
    chb_otpc2.setValue("1");
  }
};

//-------------------------------------------------------------------------
// Prepaid / Collect Type Setting
//-------------------------------------------------------------------------
scwin.f_FreightTypeSetting = function () {
  scwin.hd_frpc = "";
  scwin.hd_otpc = "";

  // WT/VAL
  if (chb_frpc1.getValue() != "0") {
    scwin.hd_frpc = "PP";
  }
  if (chb_frpc2.getValue() != "0") {
    scwin.hd_frpc = "CC";
  }
  if (chb_frpc1.getValue() != "0" && chb_frpc2.getValue() != "0") {
    scwin.hd_frpc = "PC";
  }

  // Other
  if (chb_otpc1.getValue() != "0") {
    scwin.hd_otpc = "PP";
  }
  if (chb_otpc2.getValue() != "0") {
    scwin.hd_otpc = "CC";
  }
  if (chb_otpc1.getValue() != "0" && chb_otpc2.getValue() != "0") {
    scwin.hd_otpc = "PC";
  }
};

// Airport Destination 설정
scwin.f_AirportDestination = async function () {
  var strClntNo = "";
  if ($c.str.trim($p, ed_dscd1.getValue()) != "") {
    strClntNo = $c.str.trim($p, ed_dscd1.getValue());
  }
  if ($c.str.trim($p, ed_dscd2.getValue()) != "") {
    strClntNo = $c.str.trim($p, ed_dscd2.getValue());
  }
  if ($c.str.trim($p, ed_dscd3.getValue()) != "") {
    strClntNo = $c.str.trim($p, ed_dscd3.getValue());
  }
  if (strClntNo.length > 0) {
    var params = {
      sysCd: "ilCommonEBC",
      queryId: "retrieveAirPortCode",
      param1: strClntNo,
      param2: ""
    };
    let e = await scwin.execComboAndCopy(params, {
      target: ds_AirportInfo
    });
    if (e.responseJSON.resultDataSet[0].Code < 0) {
      return;
    }
    if (ds_AirportInfo.getTotalRow() == 0) {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_046, ["Port"]);
    } else {
      ed_dsnm1.setValue(ds_AirportInfo.getCellData(0, "col2"));
    }
  } else {
    ed_dsnm1.setValue("");
  }
};

