//-------------------------------------------------------------------------
// Department 가져오기
// param1 은 A :항공,C:CONTAINER,B:BULK
//-------------------------------------------------------------------------
scwin.f_departmentInfo = async function () {
  var params = {
    sysCd: "ilCommonEBC",
    queryId: "retriveDepartmentCodeList",
    param1: "A",
    param2: $c.str.trim($p, ed_ascd.getValue())
  };
  let e = await scwin.execComboAndCopy(params, {
    target: ds_departmentInfo
  });
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  if (ds_departmentInfo.getTotalRow() == 0) {
    ed_dept.setValue("");
    txt_deptnm.setValue("");
  } else {
    var row = ds_departmentInfo.getRowPosition() || 0;
    ed_dept.setValue(ds_departmentInfo.getCellData(row, "CODE"));
    txt_deptnm.setValue(ds_departmentInfo.getCellData(row, "NAME"));
  }
};

//------------------------------------------------------------------------- 		
// customerInfo 가져오기
//------------------------------------------------------------------------- 		
scwin.f_customerInfo = async function (param) {
  var params = {
    sysCd: "ilCommonEBC",
    queryId: "retriveCustomerInfo",
    param1: param
  };
  let e = await scwin.execComboAndCopy(params, {
    target: ds_customerInfo
  });
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  if (ds_customerInfo.getRowCount() == 0) {
    return;
  }
  var row = ds_customerInfo.getRowPosition() || 0;
  ed_dept.setValue(ds_customerInfo.getCellData(row, "col1"));
  txt_deptnm.setValue(ds_customerInfo.getCellData(row, "col2"));
};

