scwin.udc_shcd_callBackFun = function (rtnList) {
  $c.gus.cfSetReturnValue($p, rtnList, ed_shcd);
  scwin.txt_shnm1 = rtnList[1] || "";
  scwin.txt_shnm2 = rtnList[2] || "";
  scwin.txt_shnm3 = rtnList[3] || "";
  scwin.txt_shnm4 = rtnList[4] || "";
  scwin.txt_shnm5 = rtnList[5] || "";
  ta_shnm.setValue(scwin.txt_shnm1 + "\n" + scwin.txt_shnm2 + "\n" + scwin.txt_shnm3 + "\n" + scwin.txt_shnm4 + "\n" + scwin.txt_shnm5);

  //Customer Info Copy
  if (ed_ascd.getValue() == "") {
    ed_ascd.setValue(ed_shcd.getValue());
    txt_asnm.setValue(scwin.txt_shnm1);
  }

  // scwin.ed_shcd_onblur 코드 옮김
  if (ed_ascd.getValue() == "") {
    ed_ascd.setValue(ed_shcd.getValue());
    txt_asnm.setValue(scwin.txt_shnm1);
  }
  if (ed_dept.getValue() == "") {
    scwin.f_departmentInfo();
  }

  // f_RetrieveCustomerBookingResult 이후 Shipper 팝업이 오픈되는데 팝업에서는 데이터가 없지만 blur로는 데이터가 set되는 현상 때문에 추가
  if (scwin.afterSetBookinfNo) {
    ed_shcd.setValue(ds_CustomerBookingInfo.getCellData(0, "shcd"));
    scwin.ed_shcd_onblur();
    scwin.afterSetBookinfNo = false;
  }
};
