//-------------------------------------------------------------------------
// Result Date의 회계마감 여부를 체크하는 함수
//-------------------------------------------------------------------------
scwin.f_JobCloseYn = async function () {
  var preWrkNo = "FI01"; // 월 마감코드

  var minRsltsDt = scwin.strCurDate.substring(0, 6) || "";

  //Selling List 실적일자 회계마감 여부 CHECK	 
  for (var i = 0; i < ds_SellingFreightInfo_freight.getRowCount(); i++) {
    var st = ds_SellingFreightInfo_freight.getRowStatus(i);
    if (st == "C") {
      //운임 신규 생성일때
      var rsltsStdDt = ds_SellingFreightInfo_freight.getCellData(i, "rsltsStdDt");
      if (rsltsStdDt && rsltsStdDt.substring(0, 6) < minRsltsDt) {
        minRsltsDt = rsltsStdDt.substring(0, 6);
      }
      var rsltsDt = minRsltsDt;
      var isCloseDepr = await udc_cfJobCloseYN.cfJobCloseYN("CUR", rsltsDt, "00", preWrkNo, "0", "", "", "000");
      if (isCloseDepr == "2" || isCloseDepr == "DNF") {
        await $c.gus.cfAlertMsg($p, "회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nSelling List Result Date를 확인하세요.");
        return false;
      }
    }
  }

  //Partner List 실적일자 회계마감 여부 CHECK
  for (var i = 0; i < ds_PartnerFreightInfo_freight.getRowCount(); i++) {
    var st = ds_PartnerFreightInfo_freight.getRowStatus(i);
    if (st == "C") {
      //운임 신규 생성일때
      var rsltsStdDt = ds_PartnerFreightInfo_freight.getCellData(i, "rsltsStdDt");
      if (rsltsStdDt && rsltsStdDt.substring(0, 6) < minRsltsDt) {
        minRsltsDt = rsltsStdDt.substring(0, 6);
      }
      var rsltsDt = minRsltsDt;
      var isCloseDepr = await udc_cfJobCloseYN.cfJobCloseYN("CUR", rsltsDt, "00", preWrkNo, "0", "", "", "000");
      if (isCloseDepr == "2" || isCloseDepr == "DNF") {
        await $c.gus.cfAlertMsg($p, "회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nPartner List Result Date를 확인하세요.");
        return false;
      }
    }
  }

  //Buying List 실적일자 회계마감 여부 CHECK
  for (var i = 0; i < ds_BuyingFreightInfo_freight.getRowCount(); i++) {
    var st = ds_BuyingFreightInfo_freight.getRowStatus(i);
    if (st == "C") {
      //운임 신규 생성일때
      var rsltsStdDt = ds_BuyingFreightInfo_freight.getCellData(i, "rsltsStdDt");
      if (rsltsStdDt && rsltsStdDt.substring(0, 6) < minRsltsDt) {
        minRsltsDt = rsltsStdDt.substring(0, 6);
      }
      var rsltsDt = minRsltsDt;
      var isCloseDepr = await udc_cfJobCloseYN.cfJobCloseYN("CUR", rsltsDt, "00", preWrkNo, "0", "", "", "000");
      if (isCloseDepr == "2" || isCloseDepr == "DNF") {
        await $c.gus.cfAlertMsg($p, "회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nBuying List Result Date를 확인하세요.");
        return false;
      }
    }
  }
  return true;
};

