//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  if (scwin.actionFlag == "Create" || scwin.actionFlag == "Copy") {
    if (lc_shipGb.getSelectedIndex() == 0) {
      ed_mblno.setValue(ed_blno.getValue());
    }
    scwin.f_ProcessBinding(dma_HouseBillSearch, "HouseBillSearch");
    var eCheck = await $c.sbm.execute($p, sbm_RetrieveHouseBillCheck);
    if (eCheck.responseJSON.resultDataSet[0].Code < 0) {
      return;
    } else {
      scwin.sbm_RetrieveHouseBillCheck_submitdone(eCheck);
    }
    if (scwin.processFlag == "Exist") {
      await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_011, ["House B/L No"]); // 이미 존재하는 @ 입니다.
      ed_blno.focus();
      return false;
    }
    ds_HouseBillInfo.modifyRowStatus(ds_HouseBillInfo.getRowPosition(), "C");
  }
  scwin.f_TextareaSave();
  scwin.f_FreightTypeSetting();
  scwin._syncHiddenDisplayToHouseInfo();

  //freight
  if (!(await scwin.f_Save_freight())) {
    return false;
  }
  if (ds_HouseBillInfo.getModifiedIndex().length != 0 || ds_HouseLicenseInfo.getModifiedIndex().length != 0 || ds_HouseFreightInfo_freight.getModifiedIndex().length != 0) {
    scwin.f_ProcessBinding(ds_HouseBillInfo, "HouseBillSave");
    scwin.f_ProcessBinding(ds_HouseLicenseInfo, "HouseLicenseSave");
    scwin.f_selectTabMenu(0); // 저장 전 TAB FOCUS 이동
    scwin.f_FreightTypeSetting();
    if (await scwin.f_ReqFieldChk()) {
      scwin.actionFlag = "Save";
      scwin.f_HblNoStockPram();
      var row = ds_HouseBillInfo.getRowPosition() || 0;
      if (ds_HouseBillInfo.getCellData(row, "status") == "U") {
        ds_HouseBillInfo.setCellData(row, "status", "");
      } else {
        ds_HouseBillInfo.setCellData(row, "status", "U");
      }
      if (ed_shCtcd.getValue() == "") {
        await $c.win.alert($p, "Shipper Country code is mandatory.");
        return false;
      }
      if (ed_cnCtcd.getValue() == "") {
        await $c.win.alert($p, "Consignee Country code is mandatory.");
        return false;
      }

      // B/L PIC값이 없을때 등록자 아이디로 입력(PIC값이 null되는걸 방지)
      if (ed_blpic.getValue() == "") {
        txt_blpic.setValue("");
        ds_HouseBillInfo.setCellData(row, "pic", scwin.userId);
      }
      scwin.f_chkDataLength(); //컬럼자릿수체크

      scwin.f_BookingSetting();
      if (ds_HouseBillInfo.getCellData(row, "shipgb") == "D") {
        // shipgb
        scwin.f_MasterBlSetting();
      }

      // asis에서는 sbm_Save submit 이후 성공/실패 여부에 관계없이 실행되어야 하는데 tobe 구조상 불가능해서 먼저 실행하도록 함
      await scwin.f_Set("SAVE");
      ds_resultHblnoMsg.removeAll();
      $c.sbm.execute($p, sbm_Save);
    }
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_001, ["House Info222"]); //@은(는) 변경된 사항이 없습니다.
  }
};
