// 유효성 검사
scwin.f_ReqFieldChk = async function () {
  if (scwin.txt_shnm1 == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Shipper Name"]);
    // txt_shnm1.focus();
    return false;
  }
  if (scwin.txt_shnm2 == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Shipper Name"]);
    // txt_shnm2.focus();
    return false;
  }
  if (scwin.txt_cnnm1 == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Consignee Name"]);
    // txt_cnnm1.focus();
    return false;
  }
  if (scwin.txt_cnnm2 == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Consignee Name"]);
    // txt_cnnm2.focus();
    return false;
  }
  if (ed_ondt.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Onboard Date"]);
    ed_ondt.focus();
    return false;
  }
  if (ed_avdt.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Arrival Date"]);
    ed_avdt.focus();
    return false;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_ondt.getValue(), ed_avdt.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, ["Onboard Date", "Arrival Date"]);
    ed_ondt.focus();
    return false;
  }
  var ondt = scwin._toDate(ed_ondt.getValue());
  var avdt = scwin._toDate(ed_avdt.getValue());
  var curDt = scwin._toDate(scwin.strCurDate);
  if ($c.gus.cfMonthsBetween($p, curDt, ondt) > 3) {
    await $c.win.alert($p, "Onboard Date가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_ondt.focus();
    return false;
  }
  if ($c.gus.cfMonthsBetween($p, curDt, avdt) > 3) {
    await $c.win.alert($p, "Arrival Date가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_avdt.focus();
    return false;
  }
  if ($c.gus.cfYearsBetween($p, ondt, curDt) > 3) {
    await $c.win.alert($p, "Onboard Date가 3년 이상의 과거 일 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_ondt.focus();
    return false;
  }
  if ($c.gus.cfYearsBetween($p, avdt, curDt) > 3) {
    await $c.win.alert($p, "Arrival Date가 3년 이상의 과거 일 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_avdt.focus();
    return false;
  }
  if ($c.date.diffDate($p, ed_ondt.getValue(), ed_avdt.getValue()) > 149) {
    await $c.win.alert($p, "Onboard Date-Arrival Date(transit time)가 150일을 초과할 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_ondt.focus();
    return false;
  }
  if ($c.str.trim($p, ed_dept.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Department Info"]);
    ed_dept.focus();
    return false;
  }
  if ($c.str.trim($p, ed_sacd.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Salesman Info"]);
    ed_sacd.focus();
    return false;
  }
  if ($c.str.trim($p, ed_itcd.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Item Info"]);
    ed_itcd.focus();
    return false;
  }
  if ($c.str.trim($p, ed_ediwht.getValue()) == "" || $c.str.trim($p, ed_ediwht.getValue()) == "0") {
    ed_ediwht.setValue(ed_mftwht.getValue());
  }
  if ($c.str.trim($p, ed_cjdt.getValue()) == "" || !$c.date.isDate($p, ed_cjdt.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Result Date Date"]);
    ed_cjdt.focus();
    return false;
  }
  if (ds_HouseLicenseInfo.getRowCount() > 0) {
    if ($c.str.trim($p, txt_ngnm1.getValue()) == "") {
      scwin.f_selectTabMenu(1);
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Nature of Goods Info"]);
      txt_ngnm1.focus();
      return false;
    }
  }
  if ($c.str.trim($p, ed_dept.getValue()) == "1GG") {
    await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_010, ["Department Info"]);
    ed_dept.focus();
    return false;
  }

  // await scwin.f_customerInfo($c.str.trim(ed_ascd.getValue()));
  var params = {
    sysCd: "ilCommonEBC",
    queryId: "retriveCustomerInfo",
    param1: ed_ascd.getValue()
  };
  let e = await scwin.execComboAndCopy(params, {
    target: ds_customerInfo
  });
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  if (ds_customerInfo.getRowCount() > 0) {
    var row = ds_customerInfo.getRowPosition() || 0;
    if (ed_dept.getValue() != ds_customerInfo.getCellData(row, "col1")) {
      await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_013);
      ed_dept.focus();
      return false;
    }
  }
  var validateArr = [tb_searchCondition, tbl_HouseBillInfo1, tbl_HouseBillInfo2_1, tbl_HouseBillInfo2_2, tbl_HouseBillInfo2_3, tbl_HouseBillInfo3_2, tbl_HouseBillInfo3_3, tbl_HouseBillInfo3_4, tbl_HouseBillInfo3_5];
  var ret = await $c.gus.cfValidate($p, validateArr, null, true);
  if (!ret) {
    return false;
  }

  // gr_HouseLicenseInfo
  let validArray = [{
    id: "exno",
    name: "수출신고번호",
    mandatory: true,
    length: 20
  }];
  var ret2 = await $c.gus.cfValidateGrid($p, gr_HouseLicenseInfo, null, null, validArray, "HouseLicenseInfo");
  if (!ret2) {
    return false;
  }
  for (var i = 0; i < ds_HouseLicenseInfo.getRowCount(); i++) {
    //면장 번호가 있을 경우 포장 갯수 , 중량은 반드시 0보다 커야 한다
    if ($c.str.trim($p, ds_HouseLicenseInfo.getCellData(i, "exno")) != "") {
      if (ds_HouseLicenseInfo.getCellData(i, "pkgs") == "0") {
        scwin.f_selectTabMenu(1);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["포장 갯수"]); //@는 필수입력항목입니다.
        return false;
      }
      if (ds_HouseLicenseInfo.getCellData(i, "wht") == "0") {
        scwin.f_selectTabMenu(1);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["중량"]); //@는 필수입력항목입니다.
        return false;
      }
    }

    //분할 여부가 yes일경우 분할 차수는 필수
    if ($c.str.trim($p, ds_HouseLicenseInfo.getCellData(i, "elsplgb")) == "Y") {
      if ($c.str.trim($p, ds_HouseLicenseInfo.getCellData(i, "elmid")) == "") {
        scwin.f_selectTabMenu(1);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["분할 차수 "]);
        return false;
      }
    }

    //동시 포장 기호가 있을 경우 동시 포장 수랑 , 단위 필수
    if ($c.str.trim($p, ds_HouseLicenseInfo.getCellData(i, "elcogb")) != "") {
      if (ds_HouseLicenseInfo.getCellData(i, "eldpkg") == "0") {
        scwin.f_selectTabMenu(1);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["동시 포장 수량"]);
        return false;
      }
      if ($c.str.trim($p, ds_HouseLicenseInfo.getCellData(i, "eldpkgut")) == "") {
        scwin.f_selectTabMenu(1);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["동시포장단위"]);
        return false;
      }
    }
  }
  return true;
};

