scwin.f_Delete = async function () {
  if (!(await scwin.f_Delete_freight())) {
    return false;
  }
  ;
  if (scwin.spRtn == "0") {
    await scwin.f_InvoiceCheck_All("F"); //운임 발행 여부 확인

    if (scwin.spRtn == "0") {
      scwin._deleteAll(ds_HouseBillInfo);
      scwin._deleteAll(ds_CustomerBookingInfo_booking);
      scwin._deleteAll(ds_MasterBookingList_booking);
      if (ds_HouseBillInfo.getCellData(ds_HouseBillInfo.getRowPosition() || 0, "shipgb") == "D") {
        scwin._deleteAll(ds_MasterBL_master);
      }
      if (ds_MasterBL_master.getRowStatus(ds_MasterBL_master.getRowPosition() || 0) == "R") {
        scwin._deleteAll(ds_MasterBL_master);
      }
      scwin.actionFlag = "Delete";
      ds_resultHblnoMsg.removeAll();
      var eDel = await $c.sbm.execute($p, sbm_Delete);
      if (eDel) {
        await scwin.sbm_Delete_submitdone(eDel);
      }
      ed_blno.setValue("");
      lc_hmhno.setValue("");
      ed_blno.focus();
    } else {
      await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_005); //"이미 인보이스  발행 되어 삭제 불가능 합니다."
    }
  }
};
scwin._deleteAll = function (ds) {
  for (var i = 0; i < ds.getRowCount(); i++) {
    ds.deleteRow(i);
  }
};

