scwin.f_selectTabMenu = function (idx) {
  switch (idx) {
    case 0:
      //Header tab
      buttonTable.show("");
      break;
    case 1:
      //Container tab
      buttonTable.show("");
      break;
    case 2:
      //Header tab
      buttonTable.hide();
      break;
  }
  tab_main.setSelectedTabIndex(idx);
};

