scwin.f_GridSet_freight = function (gubun) {
  switch (gubun) {
    case "Init":
    case "Retrieve":
      gr_BuyingFreightInfo_freight.setGridReadOnly(true);
      gr_SellingFreightInfo_freight.setGridReadOnly(true);
      gr_PartnerFreightInfo_freight.setGridReadOnly(true);
      ds_BuyingFreightInfo_freight.setRowPosition(0);
      ds_SellingFreightInfo_freight.setRowPosition(0);
      ds_PartnerFreightInfo_freight.setRowPosition(0);
      break;
    case "Create":
    case "Update":
      gr_BuyingFreightInfo_freight.setGridReadOnly(false);
      gr_SellingFreightInfo_freight.setGridReadOnly(false);
      gr_PartnerFreightInfo_freight.setGridReadOnly(false);
      if (gubun == "Update") {
        for (var row = 0; row < ds_SellingFreightInfo_freight.getTotalRow(); row++) {
          scwin.setGridColumnReadonly("Selling", row);
        }
        for (var row = 0; row < ds_PartnerFreightInfo_freight.getTotalRow(); row++) {
          scwin.setGridColumnReadonly("Partner", row);
        }
        for (var row = 0; row < ds_BuyingFreightInfo_freight.getTotalRow(); row++) {
          scwin.setGridColumnReadonly("Buying", row);
        }
      }
      ds_BuyingFreightInfo_freight.setRowPosition(0);
      ds_SellingFreightInfo_freight.setRowPosition(0);
      ds_PartnerFreightInfo_freight.setRowPosition(0);
      break;
    default:
      break;
  }
};
scwin.setGridColumnReadonly = function (gridGubun, row) {
  switch (gridGubun) {
    case "Selling":
      var sellColumnArr = ["bilgClntNo", "fareEngCd", "crcCd", "exRate", "fareUnit", "qty", "grossWt", "rateCls", "chgWt", "sellUpr", "sellAmt", "vatAmt", "sellAmtFcrc"];
      var sellColumnArr2 = ["rowNumSeq", "bilgClntNm", "fareGrpCd", "sellItemCd", "commItem", "certiNo"];
      var sellColumnArr3 = ["sellAmtFcrc"];
      var certiNo = ds_SellingFreightInfo_freight.getCellData(row, "certiNo");
      var crcCd = ds_SellingFreightInfo_freight.getCellData(row, "crcCd");
      scwin.setGridColumnArrReadonly(sellColumnArr, gr_SellingFreightInfo_freight, row, certiNo != "");
      scwin.setGridColumnArrReadonly(sellColumnArr2, gr_SellingFreightInfo_freight, row, true);
      scwin.setGridColumnArrReadonly(sellColumnArr3, gr_SellingFreightInfo_freight, row, crcCd == "KRW");
      break;
    case "Partner":
      var partColumnArr = ["bilgClntNo", "drcrCls", "fareEngCd", "crcCd", "exRate", "fareUnit", "qty", "chgWt", "sellUpr", "sellAmtFcrc", "sellAmt"];
      var partColumnArr2 = ["rowNumSeq", "bilgClntNm", "fareGrpCd", "sellItemCd", "certiNo", "rmk", "regName"];
      var certiNo = ds_PartnerFreightInfo_freight.getCellData(row, "certiNo");
      scwin.setGridColumnArrReadonly(partColumnArr, gr_PartnerFreightInfo_freight, row, certiNo != "");
      scwin.setGridColumnArrReadonly(partColumnArr2, gr_PartnerFreightInfo_freight, row, true);
      var drcrCls = ds_PartnerFreightInfo_freight.getCellData(row, "drcrCls");
      gr_PartnerFreightInfo_freight.setCellReadOnly(row, "vehclNo", drcrCls != "C");
      break;
    case "Buying":
      var buyColumnArr = ["pchsTyp", "pchsClntNo", "fareEngCd", "crcCd", "exRate", "fareUnit", "qty", "chgWt", "pchsUpr", "pchsAmt", "vat", "pchsAmtFcrc", "sellDeptCd"];
      var buyColumnArr2 = ["rowNumSeq", "pchsClntNm", "fareGrpCd", "selpchItemCd", "sellDeptNm", "pchsCertiNo", "regName"];
      var buyColumnArr3 = ["pchsAmtFcrc"];
      var pchsCertiNo = ds_BuyingFreightInfo_freight.getCellData(row, "pchsCertiNo");
      var crcCd = ds_BuyingFreightInfo_freight.getCellData(row, "crcCd");
      scwin.setGridColumnArrReadonly(buyColumnArr, gr_BuyingFreightInfo_freight, row, pchsCertiNo != "");
      scwin.setGridColumnArrReadonly(buyColumnArr2, gr_BuyingFreightInfo_freight, row, true);
      scwin.setGridColumnArrReadonly(buyColumnArr3, gr_BuyingFreightInfo_freight, row, crcCd == "KRW");
      break;
  }
};
scwin.setGridColumnArrReadonly = function (columnArr, grd, row, ret) {
  for (var i = 0; i < columnArr.length; i++) {
    grd.setCellReadOnly(row, columnArr[i], ret);
  }
};

