//-------------------------------------------------------------------------
// 조회조건 바인딩
//-------------------------------------------------------------------------
scwin.f_ProcessBinding_freight = function (ds, gubun) {
  var isMap = typeof ds.set === "function";
  var reset = function () {
    if (isMap) {
      ds.setEmptyValue();
    } else {
      ds.removeAll();
      ds.insertRow();
    }
  };
  var setVal = function (key, val) {
    if (isMap) {
      ds.set(key, val);
    } else {
      ds.setCellData(ds.getRowPosition(), key, val);
    }
  };
  switch (gubun) {
    case "FreightSearch":
      reset();
      setVal("kcomcd", scwin.hd_kcomcd);
      setVal("blno", $c.str.trim($p, ed_blno.getValue()));
      setVal("mhno", $c.str.trim($p, lc_hmhno.getValue()));
      setVal("iogb", scwin.hd_iogb);
      setVal("mblHblCls", "H");
      break;
    case "FreightSave":
      setVal("kcomcd", scwin.hd_kcomcd);
      setVal("blno", $c.str.trim($p, ed_blno.getValue()));
      break;
    default:
      break;
  }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve_freight = async function () {
  scwin.actionFlag = "Retrieve";
  if ($c.str.trim($p, ed_blno.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["House B/L No"]);
    ed_blno.focus();
    return false;
  }
  if ($c.str.trim($p, lc_hmhno.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Consol No"]);
    ed_blno.focus();
    return false;
  }

  // MasterFreightInfo  상속 후 Clear
  scwin.f_ProcessBinding_freight(ds_SearchInfo_freight, "FreightSearch");
  ds_HouseFreightInfo_freight.removeAll();
  ds_SellingFreightInfo_freight.removeAll();
  ds_PartnerFreightInfo_freight.removeAll();
  ds_BuyingFreightInfo_freight.removeAll();
  var eFreight = await $c.sbm.execute($p, sbm_Retrieve_freight);
  if (eFreight.responseJSON.OUT_DS1.length > 0) {
    await scwin.sbm_Retrieve_freight_submitdone(eFreight);
  }
  ds_profit_freight.removeAll();
  let e = await $c.sbm.execute($p, sbm_RetrieveProfit_freight);
  if (e.responseJSON.OUT_DS1.length > 0) {
    ds_profit_freight.setRowPosition(0);
  }

  // gr_BuyingFreightInfo_freight.setHeaderDisabled("choice", true);
  // gr_PartnerFreightInfo_freight.setHeaderDisabled("choice", true);
  // gr_SellingFreightInfo_freight.setHeaderDisabled("choice", true);
};

