scwin.f_ProcessResult_freight = async function (gubun) {
  switch (gubun) {
    case "None":
      scwin.f_Set_freight("INIT");
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_003); // 해당 되는 자료가 없습니다.	  
      ed_blno.focus();
      break;
    case "FreightInfo":
      scwin.f_Set_freight("RETRIEVE");
      if ($c.str.trim($p, lc_cucd_freight.getValue()) == "") {
        lc_cucd_freight.setValue(ds_HouseFreightInfo_freight.getCellData(ds_HouseFreightInfo_freight.getRowPosition() || 0, "cucd"));
      }
      if ($c.str.trim($p, ed_exdt_freight.getValue()) == "") {
        ed_exdt_freight.setValue(ds_HouseFreightInfo_freight.getCellData(ds_HouseFreightInfo_freight.getRowPosition() || 0, "ondt"));
      }
      scwin.f_TotalCac_freight("Selling");
      scwin.f_TotalCac_freight("Partner");
      scwin.f_TotalCac_freight("Buying");
      await scwin.f_MhnoLoading_freight();
      break;
    default:
      break;
  }
};

