scwin.f_Save_freight = async function () {
  if (ds_HouseFreightInfo_freight.getModifiedIndex().length != 0 || ds_BuyingFreightInfo_freight.getModifiedIndex().length != 0 || ds_SellingFreightInfo_freight.getModifiedIndex().length != 0 || ds_PartnerFreightInfo_freight.getModifiedIndex().length != 0) {
    scwin.f_ProcessBinding_freight(ds_HouseFreightInfo_freight, "FreightSave");
    if ((await scwin.f_ReqFieldChk_freight()) && (await scwin.f_JobCloseYn())) {
      scwin.actionFlag = "Save";

      // UserStatus-JSP 화면에 Head 와 Body(그리드)가 있을경우 Body가 변경 될 경우 무조건 Head도 서버 로 전송 해서 업데이트 하기 위해서 사용 됨
      var row = ds_HouseFreightInfo_freight.getRowPosition() || 0;
      if (ds_HouseFreightInfo_freight.getCellData(row, "status") == "U") {
        ds_HouseFreightInfo_freight.setCellData(row, "status", "");
      } else {
        ds_HouseFreightInfo_freight.setCellData(row, "status", "U");
      }
      if (await $c.win.confirm($p, E_MSG_CM_CRM_001)) {
        //저장하시겠습니까?
        scwin.v_linkcheck = "";
        return true;
      }
      return false;
    }
    return false;
  }
  return true;
};

// 유효성검사
scwin.f_ReqFieldChk_freight = async function () {
  for (var i = 0; i < ds_BuyingFreightInfo_freight.getRowCount(); i++) {
    if (ds_BuyingFreightInfo_freight.getCellData(i, "pchsTyp") == "3") {
      if (ds_BuyingFreightInfo_freight.getCellData(i, "sellDeptCd") == "") {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Inner Department"]); //@는 필수입력항목입니다.
        gr_BuyingFreightInfo_freight.setFocusedCell(i, "sellDeptCd");
        scwin.f_selectTabMenu_freight(2);
        return false;
      }
    }
  }
  for (var j = 0; j < ds_SellingFreightInfo_freight.getRowCount(); j++) {
    if (ds_SellingFreightInfo_freight.getCellData(j, "vatYn") == 0) {
      if (parseFloat(ds_SellingFreightInfo_freight.getCellData(j, "vatAmt") || 0) > 0) {
        await $c.win.alert($p, "영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nSelling List " + (j + 1) + "번째 데이터를 확인하세요.");
        gr_SellingFreightInfo_freight.setFocusedCell(j, "vatAmt");
        scwin.f_selectTabMenu_freight(2);
        return false;
      }
    }
    if (ds_SellingFreightInfo_freight.getCellData(j, "vatYn") == 1) {
      var sellAmt = parseFloat(ds_SellingFreightInfo_freight.getCellData(j, "sellAmt") || 0);
      var vatAmt = parseFloat(ds_SellingFreightInfo_freight.getCellData(j, "vatAmt") || 0);
      if (Math.abs(Math.round(sellAmt * 0.1) - vatAmt) > 1) {
        await $c.win.alert($p, "VAT 금액은 Amount(W)금액의 10%입니다.\nSelling List " + (j + 1) + "번째 금액을 확인하세요.");
        gr_SellingFreightInfo_freight.setFocusedCell(j, "vatAmt");
        return false;
      }
    }
    if (ds_SellingFreightInfo_freight.getCellData(j, "sellAmt") == "0") {
      await $c.win.alert($p, "Amount(W) 금액이 0입니다. \nSelling List " + (j + 1) + "번째 데이터를 확인하세요.");
      gr_SellingFreightInfo_freight.setFocusedCell(j, "sellAmt");
      return false;
    }
    //삭제 시 내부거래 체크
    if (ds_SellingFreightInfo_freight.getRowStatus(j) == "D") {
      await scwin.f_postDtChk(ds_SellingFreightInfo_freight.getCellData(j, "odrNo"), ds_SellingFreightInfo_freight.getCellData(j, "sellSeq"), ds_SellingFreightInfo_freight.getCellData(j, "kcomcd"), ds_SellingFreightInfo_freight.getCellData(j, "seaAirCls"), ds_SellingFreightInfo_freight.getCellData(j, "blNo"), ds_SellingFreightInfo_freight.getCellData(j, "mhno"));
      var isPostDtSell = postDtDataSet_.getCellData(0, "col1");
      if ($c.str.trim($p, isPostDtSell) != "") {
        await $c.win.alert($p, "내부거래 확정 건 입니다. \nSelling List " + (j + 1) + "번째 데이터를 확인하세요.");
        return false;
      }
    }
  }
  for (var k = 0; k < ds_PartnerFreightInfo_freight.getRowCount(); k++) {
    if (ds_PartnerFreightInfo_freight.getCellData(k, "sellAmt") == "0") {
      await $c.win.alert($p, "Amount(W) 금액이 0입니다. \nPartner List " + (k + 1) + "번째 데이터를 확인하세요.");
      gr_PartnerFreightInfo_freight.setFocusedCell(k, "sellAmt");
      scwin.f_selectTabMenu_freight(2);
      return false;
    }

    //삭제 시 내부거래 체크
    if (ds_PartnerFreightInfo_freight.getRowStatus(k) == "D") {
      await scwin.f_postDtChk(ds_PartnerFreightInfo_freight.getCellData(k, "odrNo"), ds_PartnerFreightInfo_freight.getCellData(k, "sellSeq"), ds_PartnerFreightInfo_freight.getCellData(k, "kcomcd"), ds_PartnerFreightInfo_freight.getCellData(k, "seaAirCls"), ds_PartnerFreightInfo_freight.getCellData(k, "blNo"), ds_PartnerFreightInfo_freight.getCellData(k, "mhno"));
      var isPostDtPartner = postDtDataSet_.getCellData(0, "col1");
      if ($c.str.trim($p, isPostDtPartner) != "") {
        await $c.win.alert($p, "내부거래 확정 건 입니다. \nPartner List " + (k + 1) + "번째 데이터를 확인하세요.");
        return false;
      }
    }
  }
  for (var m = 0; m < ds_BuyingFreightInfo_freight.getRowCount(); m++) {
    if (ds_BuyingFreightInfo_freight.getCellData(m, "vatYn") == 0) {
      if (parseFloat(ds_BuyingFreightInfo_freight.getCellData(m, "vat") || 0) > 0) {
        await $c.win.alert($p, "영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nBuying List " + (m + 1) + "번째 데이터를 확인하세요.");
        gr_BuyingFreightInfo_freight.setFocusedCell(m, "vat");
        scwin.f_selectTabMenu_freight(2);
        return false;
      }
    }
    if (ds_BuyingFreightInfo_freight.getCellData(m, "pchsAmt") == "0") {
      await $c.win.alert($p, "Amount(W) 금액이 0입니다. \nBuying List " + (m + 1) + "번째 데이터를 확인하세요.");
      gr_BuyingFreightInfo_freight.setFocusedCell(m, "pchsAmt");
      scwin.f_selectTabMenu_freight(2);
      return false;
    }

    //삭제 시 내부거래 체크
    if (ds_BuyingFreightInfo_freight.getRowStatus(m) == "D") {
      await scwin.f_postDtChk(ds_BuyingFreightInfo_freight.getCellData(m, "odrNo"), ds_BuyingFreightInfo_freight.getCellData(m, "pchsSeq"), ds_BuyingFreightInfo_freight.getCellData(m, "kcomcd"), ds_BuyingFreightInfo_freight.getCellData(m, "seaAirCls"), ds_BuyingFreightInfo_freight.getCellData(m, "blNo"), ds_BuyingFreightInfo_freight.getCellData(m, "mhno"));
      var isPostDtBuy = postDtDataSet_.getCellData(0, "col1");
      if ($c.str.trim($p, isPostDtBuy) != "") {
        await $c.win.alert($p, "내부거래 확정 건 입니다. \nBuying List " + (m + 1) + "번째 데이터를 확인하세요.");
        return false;
      }
    }
  }

  // ---- cfValidate([gr_BuyingFreightInfo_freight, gr_SellingFreightInfo_freight, gr_PartnerFreightInfo_freight]) == false ----
  // gr_BuyingFreightInfo_freight
  let validArrayBuy = [{
    id: "rsltsStdDt",
    name: "Result Date",
    mandatory: true,
    valid: "date",
    format: "YYYYMMDD"
  }, {
    id: "pchsTyp",
    name: "Freight Type",
    mandatory: true
  }, {
    id: "pchsClntNo",
    name: "Customer Info",
    mandatory: true
  }, {
    id: "fareEngCd",
    name: "Freight Info",
    mandatory: true
  }
  // {id:"selpchItemcd", name: "통합매출입코드", mandatory: true},
  ];
  var retBuy = await $c.gus.cfValidateGrid($p, gr_BuyingFreightInfo_freight, null, null, validArrayBuy, "House Buying");

  // gr_SellingFreightInfo_freight
  let validArraySell = [{
    id: "rsltsStdDt",
    name: "Result Date",
    mandatory: true,
    valid: "date",
    format: "YYYYMMDD"
  }, {
    id: "bilgClntNo",
    name: "Customer Info",
    mandatory: true
  }, {
    id: "fareEngCd",
    name: "Freight Info",
    mandatory: true
  }, {
    id: "sellItemCd",
    name: "통합매출입코드",
    mandatory: true
  }];
  var retSell = await $c.gus.cfValidateGrid($p, gr_SellingFreightInfo_freight, null, null, validArraySell, "House Selling");

  // gr_PartnerFreightInfo_freight
  let validArrayPart = [{
    id: "rsltsStdDt",
    name: "Result Date",
    mandatory: true,
    valid: "date",
    format: "YYYYMMDD"
  }, {
    id: "bilgClntNo",
    name: "Customer Info",
    mandatory: true
  }, {
    id: "fareEngCd",
    name: "Freight Info",
    mandatory: true
  }, {
    id: "sellItemCd",
    name: "통합매출입코드",
    mandatory: true
  }];
  var retPart = await $c.gus.cfValidateGrid($p, gr_PartnerFreightInfo_freight, null, null, validArrayPart, "House Partner");
  if (!retBuy || !retSell || !retPart) {
    return false;
  }
  return true;
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete_freight = async function () {
  if (await $c.win.confirm($p, E_MSG_CM_CRM_004)) {
    //삭제하시겠습니까?
    scwin.actionFlag = "Delete";
    await scwin.f_InvoiceCheck_freight_All_freight();
    if (scwin.spRtn == "0") {
      if (ds_HouseFreightInfo_freight.getRowCount() > 0) {
        scwin._deleteRow(ds_HouseFreightInfo_freight, ds_HouseFreightInfo_freight.getRowPosition());
      }
      for (var i = ds_BuyingFreightInfo_freight.getRowCount() - 1; i >= 0; i--) {
        scwin._deleteRow(ds_BuyingFreightInfo_freight, i);
      }
      for (var j = ds_SellingFreightInfo_freight.getRowCount() - 1; j >= 0; j--) {
        scwin._deleteRow(ds_SellingFreightInfo_freight, j);
      }
      for (var k = ds_PartnerFreightInfo_freight.getRowCount() - 1; k >= 0; k--) {
        scwin._deleteRow(ds_PartnerFreightInfo_freight, k);
      }
      // await $c.sbm.execute(sbm_Save_freight);
    } else {
      await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_012);
    }
    return true;
  }
  return false;
};

