//-------------------------------------------------------------------------
// 다중행추가
//-------------------------------------------------------------------------
scwin.f_AddRowMulti_freight = function (gubun) {
  var rowMakeSelling = ed_rowMake_selling.getValue() == "" ? 1 : parseInt(ed_rowMake_selling.getValue(), 10);
  var rowMakePartner = ed_rowMake_partner.getValue() == "" ? 1 : parseInt(ed_rowMake_partner.getValue(), 10);
  var rowMakeBuying = ed_rowMake_buying.getValue() == "" ? 1 : parseInt(ed_rowMake_buying.getValue(), 10);
  switch (gubun) {
    case "Selling":
      for (var i = 0; i < rowMakeSelling; i++) {
        scwin.f_AddRow_freight("Selling");
      }
      break;
    case "Partner":
      for (var j = 0; j < rowMakePartner; j++) {
        scwin.f_AddRow_freight("Partner");
      }
      break;
    case "Buying":
      for (var k = 0; k < rowMakeBuying; k++) {
        scwin.f_AddRow_freight("Buying");
      }
      break;
    default:
      break;
  }
};

//-------------------------------------------------------------------------
// 전체 행삭제
//-------------------------------------------------------------------------
scwin.f_DeleteAllRow_freight = async function (gubun) {
  var ds = null;
  switch (gubun) {
    case "Selling":
      ds = ds_SellingFreightInfo_freight;
      break;
    case "Partner":
      ds = ds_PartnerFreightInfo_freight;
      break;
    case "Buying":
      ds = ds_BuyingFreightInfo_freight;
      break;
    default:
      break;
  }
  if (!ds) return;
  for (var i = ds.getRowCount() - 1; i >= 0; i--) {
    ds.setRowPosition(i);
    await scwin.f_DeleteRow_freight(gubun);
  }
};

//-------------------------------------------------------------------------
// 그리드 행삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow_freight = async function (gubun) {
  var tmp = null;
  var tmpCnt = null;
  var certiCol = "";
  switch (gubun) {
    case "Selling":
      tmp = ds_SellingFreightInfo_freight;
      tmpCnt = totalRowSelling;
      certiCol = "certiNo";
      break;
    case "Partner":
      tmp = ds_PartnerFreightInfo_freight;
      tmpCnt = totalRowPartner;
      certiCol = "certiNo";
      break;
    case "Buying":
      tmp = ds_BuyingFreightInfo_freight;
      tmpCnt = totalRowBuying;
      certiCol = "pchsCertiNo";
      break;
    default:
      break;
  }
  if (!tmp) return;
  var rowPos = tmp.getRowPosition();
  for (var i = tmp.getRowCount() - 1; i >= 0; i--) {
    if (tmp.getCellData(i, "choice") == "T" || i == rowPos) {
      if (tmp.getCellData(i, certiCol) == "") {
        if (tmp.getRowStatus(rowPos) == "C") {
          tmp.removeRow(rowPos);
        } else {
          tmp.deleteRow(rowPos);
          tmp.setRowPosition(rowPos);
        }
      } else {
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
        return;
      }
    }
  }
  for (var i = 0; i < tmp.getRowCount(); i++) {
    if (tmp.getRowStatus(i) != "R") {
      scwin.setRowNumSeq(tmp, i);
    }
  }
  tmpCnt.setValue(tmp.getTotalRow());
};

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_UndoRow_freight = function (gubun) {
  var tmp;
  switch (gubun) {
    case "Selling":
      tmp = ds_SellingFreightInfo_freight;
      tmpCnt = totalRowSelling;
      break;
    case "Partner":
      tmp = ds_PartnerFreightInfo_freight;
      tmpCnt = totalRowPartner;
      break;
    case "Buying":
      tmp = ds_BuyingFreightInfo_freight;
      tmpCnt = totalRowBuying;
      break;
    default:
      break;
  }

  // $c.data.undoRow(tmp, "Y");
  $c.data.undoAll($p, tmp);
  for (var i = 0; i < tmp.getRowCount(); i++) {
    if (tmp.getRowStatus(i) != "R") {
      scwin.setRowNumSeq(tmp, i);
    } else if (tmp.getRowStatus(i) == "R") {
      scwin.setRowNumSeq(tmp, i);
      tmp.modifyRowStatus(i, "R");
    }
  }
  tmpCnt.setValue(tmp.getTotalRow());
};

