//-------------------------------------------------------------------------
// MHNO 가져오기
//-------------------------------------------------------------------------
scwin.f_MhnoLoading_freight = async function () {
  var strClntNo = $c.str.trim($p, ed_blno.getValue());
  if (strClntNo.length > 0) {
    var params = {
      sysCd: "ilCommonEBC",
      queryId: "retriveAirHouseMhnoListCombo",
      param1: strClntNo,
      param2: scwin.hd_iogb
    };
    let e = await scwin.execComboAndCopy(params, {
      target: ds_hmhno
    });
    if (e) {
      await scwin.ds_hmhno_OnLoadCompleted();
    }
  } else {
    ds_hmhno.removeAll();
    lc_hmhno.setValue("");
  }
};

//-------------------------------------------------------------------------
// 환율정보 가져오기
//-------------------------------------------------------------------------
scwin.f_ExrateLoading_freight = async function (param1, param2, param3) {
  if (param1 && param1.length > 0) {
    var p1 = param1;
    if (p1 == "KRW") {
      p1 = "USD";
    }
    var params = {
      sysCd: "ilCommonEBC",
      queryId: "retrieveExRate",
      param1: p1,
      param2: param2,
      param3: param3
    };
    await scwin.execComboAndCopy(params, {
      target: ds_ExRate_freight
    });
  }
};

//-------------------------------------------------------------------------
// Pkg/Weight Setting
//-------------------------------------------------------------------------
scwin.f_PkgWegihtSetting_freight = function (row, colid, gubun) {
  var dsHouse = ds_HouseFreightInfo_freight;
  var houseRow = dsHouse.getRowPosition();
  if (houseRow < 0) houseRow = 0;
  switch (gubun) {
    case "Selling":
      {
        var dsSelling = ds_SellingFreightInfo_freight;
        if (colid == "fareEngCd") {
          dsSelling.setCellData(row, "grossWt", dsHouse.getCellData(houseRow, "mftwht"));
          dsSelling.setCellData(row, "chgWt", dsHouse.getCellData(houseRow, "tcwht"));
        }
        break;
      }
    case "Partner":
      {
        var dsPartner = ds_PartnerFreightInfo_freight;
        if (colid == "fareEngCd") {
          dsPartner.setCellData(row, "grossWt", 0);
          dsPartner.setCellData(row, "chgWt", dsHouse.getCellData(houseRow, "tcwht"));
        }
        break;
      }
    case "Buying":
      {
        var dsBuying = ds_BuyingFreightInfo_freight;
        if (colid == "fareEngCd") {
          dsBuying.setCellData(row, "grossWt", dsHouse.getCellData(houseRow, "mftwht"));
          dsBuying.setCellData(row, "chgWt", dsHouse.getCellData(houseRow, "tcwht"));
        }
        break;
      }
    default:
      break;
  }
};

//-------------------------------------------------------------------------
// Rate Amount 계산
//-------------------------------------------------------------------------
scwin.f_RateAmount_freight = function (row, colid, gubun, olddata) {
  function toNum(v) {
    return parseFloat(v || 0);
  }
  switch (gubun) {
    case "Selling":
      {
        var dsSelling = ds_SellingFreightInfo_freight;
        var nUnit = scwin.f_Currency_Unit_freight(dsSelling.getCellData(row, "crcCd"));
        if (colid == "sellUpr" && dsSelling.getCellData(row, colid) != olddata || colid == "qty" && dsSelling.getCellData(row, colid) != olddata) {
          var cWeight = toNum(dsSelling.getCellData(row, "qty"));
          var exRate = toNum(dsSelling.getCellData(row, "exRate"));
          if (dsSelling.getCellData(row, "crcCd") == "KRW") {
            var amount = Math.round(cWeight * toNum(dsSelling.getCellData(row, "sellUpr")));
            dsSelling.setCellData(row, "sellAmt", amount);
            if (dsSelling.getCellData(row, "vatYn") == 0) {
              dsSelling.setCellData(row, "vatAmt", 0);
            } else {
              dsSelling.setCellData(row, "vatAmt", Math.round(amount * 0.1));
            }

            //Selling,Buying 은 원화 일경우 외화 무조건 0
            dsSelling.setCellData(row, "sellAmtFcrc", 0);
          } else {
            var amountF = Math.round(cWeight * toNum(dsSelling.getCellData(row, "sellUpr")) * 100) / 100;
            dsSelling.setCellData(row, "sellAmtFcrc", amountF);
            dsSelling.setCellData(row, "sellAmt", Math.round(amountF * exRate / nUnit));
            if (dsSelling.getCellData(row, "vatYn") == 0) {
              dsSelling.setCellData(row, "vatAmt", 0);
            } else {
              dsSelling.setCellData(row, "vatAmt", Math.round(amountF * exRate / nUnit * 0.1));
            }
          }

          // 원화 amount 변경 시 외화 amount 수정 	
        } else if (colid == "sellAmt" && dsSelling.getCellData(row, colid) != olddata) {
          var exRate2 = toNum(dsSelling.getCellData(row, "exRate"));
          var amountW = toNum(dsSelling.getCellData(row, "sellAmt"));
          if (dsSelling.getCellData(row, "vatYn") == 0) {
            dsSelling.setCellData(row, "vatAmt", 0);
          } else {
            dsSelling.setCellData(row, "vatAmt", Math.round(amountW * 0.1));
          }
          if (dsSelling.getCellData(row, "crcCd") == "KRW") {
            dsSelling.setCellData(row, "sellAmtFcrc", 0);
          } else {
            dsSelling.setCellData(row, "sellAmtFcrc", Math.round(amountW * nUnit / exRate2 * 100) / 100);
          }
        } else if (colid == "sellAmtFcrc" && dsSelling.getCellData(row, colid) != olddata || colid == "exRate" && dsSelling.getCellData(row, colid) != olddata) {
          var exRate3 = toNum(dsSelling.getCellData(row, "exRate"));
          var amountF2 = toNum(dsSelling.getCellData(row, "sellAmtFcrc"));
          if (dsSelling.getCellData(row, "vatYn") == 0) {
            //부가세 재 계산
            dsSelling.setCellData(row, "vatAmt", 0);
          } else {
            dsSelling.setCellData(row, "vatAmt", Math.round(amountF2 * exRate3 / nUnit * 0.1));
          }
          dsSelling.setCellData(row, "sellAmt", Math.round(amountF2 * exRate3 / nUnit));
        }
        break;
      }
    case "Partner":
      {
        var dsPartner = ds_PartnerFreightInfo_freight;
        var nUnitP = scwin.f_Currency_Unit_freight(dsPartner.getCellData(row, "crcCd"));
        if (colid == "sellUpr" && dsPartner.getCellData(row, colid) != olddata || colid == "qty" && dsPartner.getCellData(row, colid) != olddata) {
          var cWeightP = toNum(dsPartner.getCellData(row, "qty"));
          var exRateP = toNum(dsPartner.getCellData(row, "exRate"));
          if (dsPartner.getCellData(row, "crcCd") == "KRW") {
            var amountP = Math.round(cWeightP * toNum(dsPartner.getCellData(row, "sellUpr")));
            dsPartner.setCellData(row, "sellAmt", amountP);
            if (dsPartner.getCellData(row, "vatYn") == 0) {
              dsPartner.setCellData(row, "vatAmt", 0);
            } else {
              dsPartner.setCellData(row, "vatAmt", Math.round(amountP * 0.1));
            }
            dsPartner.setCellData(row, "sellAmtFcrc", Math.round(amountP * nUnitP / exRateP * 100) / 100);
          } else {
            var amountPF = Math.round(cWeightP * toNum(dsPartner.getCellData(row, "sellUpr")) * 100) / 100;
            dsPartner.setCellData(row, "sellAmtFcrc", amountPF);
            dsPartner.setCellData(row, "sellAmt", Math.round(amountPF * exRateP / nUnitP));
            if (dsPartner.getCellData(row, "vatYn") == 0) {
              dsPartner.setCellData(row, "vatAmt", 0);
            } else {
              dsPartner.setCellData(row, "vatAmt", Math.round(amountPF * exRateP / nUnitP * 0.1));
            }
          }
        } else if (colid == "sellAmt" && dsPartner.getCellData(row, colid) != olddata) {
          // 원화 amount 변경 시 외화 amount 수정 
          var exRateP2 = toNum(dsPartner.getCellData(row, "exRate"));
          var amountPW = toNum(dsPartner.getCellData(row, "sellAmt"));
          if (dsPartner.getCellData(row, "vatYn") == 0) {
            dsPartner.setCellData(row, "vatAmt", 0);
          } else {
            dsPartner.setCellData(row, "vatAmt", Math.round(amountPW * 0.1));
          }
          dsPartner.setCellData(row, "sellAmtFcrc", Math.round(amountPW * nUnitP / exRateP2 * 100) / 100);
        } else if (colid == "sellAmtFcrc" && dsPartner.getCellData(row, colid) != olddata || colid == "exRate" && dsPartner.getCellData(row, colid) != olddata) {
          var exRateP3 = toNum(dsPartner.getCellData(row, "exRate"));
          var amountPF2 = toNum(dsPartner.getCellData(row, "sellAmtFcrc"));
          dsPartner.setCellData(row, "sellAmt", Math.round(amountPF2 * exRateP3 / nUnitP));
          if (dsPartner.getCellData(row, "vatYn") == 0) {
            dsPartner.setCellData(row, "vatAmt", 0);
          } else {
            dsPartner.setCellData(row, "vatAmt", Math.round(amountPF2 * exRateP3 / nUnitP * 0.1));
          }

          //파트너  외화 변경시 rate변경 되게 수정
          var cWeightP2 = toNum(dsPartner.getCellData(row, "qty"));
          if (cWeightP2 != 0) {
            dsPartner.setCellData(row, "sellUpr", Math.round((amountPF2 / cWeightP2 - 0.005) * 100) / 100);
          }
        }
        break;
      }
    case "Buying":
      {
        var dsBuying = ds_BuyingFreightInfo_freight;
        var nUnitB = scwin.f_Currency_Unit_freight(dsBuying.getCellData(row, "crcCd"));
        if (colid == "pchsUpr" && dsBuying.getCellData(row, colid) != olddata || colid == "qty" && dsBuying.getCellData(row, colid) != olddata) {
          var cWeightB = toNum(dsBuying.getCellData(row, "qty"));
          var exRateB = toNum(dsBuying.getCellData(row, "exRate"));
          if (dsBuying.getCellData(row, "crcCd") == "KRW") {
            var amountB = Math.round(cWeightB * toNum(dsBuying.getCellData(row, "pchsUpr")));
            dsBuying.setCellData(row, "prtnAmt", amountB);
            dsBuying.setCellData(row, "pchsAmt", amountB);
            if (dsBuying.getCellData(row, "vatYn") == 0) {
              dsBuying.setCellData(row, "vat", 0);
            } else {
              dsBuying.setCellData(row, "vat", Math.round(amountB * 0.1 - 0.5));
            }
            dsBuying.setCellData(row, "pchsAmtFcrc", 0);
          } else {
            var amountBF = Math.round(cWeightB * toNum(dsBuying.getCellData(row, "pchsUpr")) * 100) / 100;
            dsBuying.setCellData(row, "pchsAmtFcrc", amountBF);
            dsBuying.setCellData(row, "prtnAmt", Math.round(amountBF * exRateB / nUnitB));
            dsBuying.setCellData(row, "pchsAmt", Math.round(amountBF * exRateB / nUnitB));
            if (dsBuying.getCellData(row, "vatYn") == 0) {
              dsBuying.setCellData(row, "vat", 0);
            } else {
              dsBuying.setCellData(row, "vat", Math.round(amountBF * exRateB / nUnitB * 0.1 - 0.5));
            }
            gr_BuyingFreightInfo_freight.setFocusedCell(row, "pchsAmtFcrc");
          }
        } else if (colid == "pchsAmt" && dsBuying.getCellData(row, colid) != olddata) {
          var exRateB2 = toNum(dsBuying.getCellData(row, "exRate"));
          var amountBW = toNum(dsBuying.getCellData(row, "pchsAmt"));
          if (dsBuying.getCellData(row, "vatYn") == 0) {
            dsBuying.setCellData(row, "vat", 0);
          } else {
            dsBuying.setCellData(row, "vat", Math.round(amountBW * 0.1 - 0.5));
          }
          if (dsBuying.getCellData(row, "crcCd") == "KRW") {
            dsBuying.setCellData(row, "pchsAmtFcrc", 0);
          } else {
            dsBuying.setCellData(row, "pchsAmtFcrc", Math.round(amountBW * nUnitB / exRateB2 * 100) / 100);
          }
        } else if (colid == "pchsAmtFcrc" && dsBuying.getCellData(row, colid) != olddata || colid == "exRate" && dsBuying.getCellData(row, colid) != olddata) {
          var exRateB3 = toNum(dsBuying.getCellData(row, "exRate"));
          var amountBF2 = toNum(dsBuying.getCellData(row, "pchsAmtFcrc"));
          if (dsBuying.getCellData(row, "vatYn") == 0) {
            dsBuying.setCellData(row, "vatAmt", 0);
          } else {
            dsBuying.setCellData(row, "vatAmt", Math.round(amountBF2 * exRateB3 / nUnitB * 0.1));
          }
          dsBuying.setCellData(row, "pchsAmt", Math.round(amountBF2 * exRateB3 / nUnitB));
        }
        break;
      }
    default:
      break;
  }
};

//-------------------------------------------------------------------------
// Currency 에 따른 Ex-Rate 적용
//-------------------------------------------------------------------------
scwin.f_CurrRateSetting_freight = async function (row, colid, disGubun) {
  var param1 = "";
  var param2 = "";
  var param3 = "";
  switch (disGubun) {
    case "Selling":
      {
        var dsSelling = ds_SellingFreightInfo_freight;
        if (dsSelling.getCellData(row, "crcCd") == $c.str.trim($p, lc_cucd_freight.getValue())) {
          dsSelling.setCellData(row, "exRate", ed_rate_freight.getValue());
        } else {
          param1 = dsSelling.getCellData(row, "crcCd");
          param2 = $c.str.trim($p, ed_exdt_freight.getValue());
          param3 = $c.str.trim($p, lc_exgb_freight.getValue());
          await scwin.f_ExrateLoading_freight(param1, param2, param3);
          if (ds_ExRate_freight.getRowCount() > 0) {
            dsSelling.setCellData(row, "exRate", ds_ExRate_freight.getCellData(0, "code"));
          }
        }
        break;
      }
    case "Partner":
      {
        var dsPartner = ds_PartnerFreightInfo_freight;
        if (dsPartner.getCellData(row, "crcCd") == $c.str.trim($p, lc_cucd_freight.getValue())) {
          dsPartner.setCellData(row, "exRate", ed_rate_freight.getValue());
        } else {
          param1 = dsPartner.getCellData(row, "crcCd");
          param2 = $c.str.trim($p, ed_exdt_freight.getValue());
          param3 = $c.str.trim($p, lc_exgb_freight.getValue());
          await scwin.f_ExrateLoading_freight(param1, param2, param3);
          if (ds_ExRate_freight.getRowCount() > 0) {
            dsPartner.setCellData(row, "exRate", ds_ExRate_freight.getCellData(0, "code"));
          }
        }
        break;
      }
    case "Buying":
      {
        var dsBuying = ds_BuyingFreightInfo_freight;
        if (dsBuying.getCellData(row, "crcCd") == $c.str.trim($p, lc_cucd_freight.getValue())) {
          dsBuying.setCellData(row, "exRate", ed_rate_freight.getValue());
        } else {
          param1 = dsBuying.getCellData(row, "crcCd");
          param2 = $c.str.trim($p, ed_exdt_freight.getValue());
          param3 = $c.str.trim($p, lc_exgb_freight.getValue());
          await scwin.f_ExrateLoading_freight(param1, param2, param3);
          if (ds_ExRate_freight.getRowCount() > 0) {
            dsBuying.setCellData(row, "exRate", ds_ExRate_freight.getCellData(0, "code"));
          }
        }
        break;
      }
    default:
      break;
  }
};

