//-------------------------------------------------------------------------
// Total 계산
//-------------------------------------------------------------------------
scwin.f_TotalCac_freight = function (gubun) {
  switch (gubun) {
    case "Selling":
      {
        var dsSelling = ds_SellingFreightInfo_freight;
        var sellingUtotal = 0;
        var sellingTotal = 0;
        var sellingTotalVat = 0;
        for (var i = 0; i < dsSelling.getRowCount(); i++) {
          if (dsSelling.getRowStatus(i) != "D") {
            sellingUtotal += parseFloat(dsSelling.getCellData(i, "sellAmtFcrc") || 0);
            sellingTotal += parseFloat(dsSelling.getCellData(i, "sellAmt") || 0);
            sellingTotalVat += parseFloat(dsSelling.getCellData(i, "vatAmt") || 0);
          }
        }
        ed_Selling_utotal.setValue(sellingUtotal);
        ed_Selling_total_freight.setValue(sellingTotal);
        ed_Selling_total_freightVat.setValue(sellingTotalVat);
        break;
      }
    case "Partner":
      {
        var dsPartner = ds_PartnerFreightInfo_freight;
        var partnerUtotal = 0;
        var partnerTotal = 0;
        var partnerTotalVat = 0;
        for (var j = 0; j < dsPartner.getRowCount(); j++) {
          if (dsPartner.getRowStatus(j) != "D") {
            partnerUtotal += parseFloat(dsPartner.getCellData(j, "sellAmtFcrc") || 0);
            partnerTotal += parseFloat(dsPartner.getCellData(j, "sellAmt") || 0);
            partnerTotalVat += parseFloat(dsPartner.getCellData(j, "vatAmt") || 0);
          }
        }
        ed_Partner_utotal.setValue(partnerUtotal);
        ed_Partner_total.setValue(partnerTotal);
        ed_Partner_totalVat.setValue(partnerTotalVat);
        break;
      }
    case "Buying":
      {
        var dsBuying = ds_BuyingFreightInfo_freight;
        var buyingUtotal = 0;
        var buyingTotal = 0;
        var buyingTotalVat = 0;
        for (var k = 0; k < dsBuying.getRowCount(); k++) {
          if (dsBuying.getRowStatus(k) != "D") {
            buyingUtotal += parseFloat(dsBuying.getCellData(k, "pchsAmtFcrc") || 0);
            buyingTotal += parseFloat(dsBuying.getCellData(k, "pchsAmt") || 0);
            buyingTotalVat += parseFloat(dsBuying.getCellData(k, "vat") || 0);
          }
        }
        ed_Buying_utotal.setValue(buyingUtotal);
        ed_Buying_total.setValue(buyingTotal);
        ed_Buying_totalVat.setValue(buyingTotalVat);
        ed_Buying_totalVatSum.setValue(buyingTotal + buyingTotalVat);
        break;
      }
    default:
      break;
  }
};

