//-------------------------------------------------------------------------
// Tariff 적용
//-------------------------------------------------------------------------
scwin.f_Tariff_freight = async function () {
  var rtnList;
  switch (scwin.tabIndex) {
    case 2:
      {
        // Buying
        var row = ds_HouseFreightInfo_freight.getRowPosition() || 0;
        if (ds_HouseFreightInfo_freight.getCellData(row, "lrgb") != "S") {
          //return;
        }
        var dsBuying = ds_BuyingFreightInfo_freight;
        if (dsBuying.getRowCount() > 0) {
          await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_011, ["House Buying"]); // @ 운임 자료가 존재 합니다. 삭제 후 적용 하세요.
        } else {
          await scwin.f_AirFreightTariff_freight("Buying"); //항공운임 aaf tariff 조회 

          if (ds_AirFreightTariff_freight.getRowCount() > 0) {
            rtnList = await scwin.f_AirFreightTariffCalc_freight("Buying");

            // 그리드 ROW 추가 
            await scwin.f_FreightCodeInfo_freight("AAF", "");
            scwin.f_AddRow_freight("Buying");
            var row = dsBuying.getRowPosition() || 0;
            dsBuying.setCellData(row, "pchsTyp", "2");
            dsBuying.setCellData(row, "fareEngCd", ds_FcodeInfo_freight.getCellData(0, "col1"));
            dsBuying.setCellData(row, "fareEngNm", ds_FcodeInfo_freight.getCellData(0, "col2"));
            dsBuying.setCellData(row, "fareGrpCd", ds_FcodeInfo_freight.getCellData(0, "col6"));
            dsBuying.setCellData(row, "selpchItemCd", ds_FcodeInfo_freight.getCellData(0, "col4"));
            dsBuying.setCellData(row, "vatYn", ds_FcodeInfo_freight.getCellData(0, "col8"));

            // CurrencyRateSetting
            // Tariff 적용은 KRW 로 적용한다.
            dsBuying.setCellData(row, "crcCd", "KRW");
            await scwin.f_CurrRateSetting_freight(row, "crcCd", "Buying");
            scwin.f_PkgWegihtSetting_freight(row, "fareEngCd", "Buying");
            if (dsBuying.getCellData(row, "chgWt") < rtnList[0]) {
              dsBuying.setCellData(row, "chgWt", rtnList[0]);
            }
            dsBuying.setCellData(row, "pchsUpr", rtnList[1]);
            dsBuying.setCellData(row, "trfUpr", rtnList[1]);
            dsBuying.setCellData(row, "pchsAmt", rtnList[2]);
            dsBuying.setCellData(row, "rateCls", rtnList[4]);
          }
          await scwin.f_AirOtherTariff_freight("Buying"); //항공 other tariff 조회

          if (ds_AirOtherTariff_freight.getRowCount() > 0) {
            await scwin.f_AirOtherTariffCalc_freight("Buying");
          }
          var params = {
            sysCd: "CoCommonEBC",
            queryId: "retrieveCoCargoPickupInfoDTOList",
            param1: "H",
            param2: scwin.hd_kcomcd,
            param3: ds_HouseFreightInfo_freight.getCellData(ds_HouseFreightInfo_freight.getRowPosition(), "blno")
          };
          let e = await scwin.execComboAndCopy(params, {
            target: ds_AirCustBookingCargoPickupList_freight
          });
          if (e.responseJSON.resultDataSet[0].Code < 0) return;
          for (var i = 0; i < ds_AirCustBookingCargoPickupList_freight.getRowCount(); i++) {
            await scwin.f_AirTruckingTariff_freight(i, "Buying");
            if (ds_AirTruckingTariff_freight.getRowCount() >= 1) {
              await scwin.f_AirTruckingTariffCalc_freight(i, "Buying");
            }
          }
        }
        break;
      }
    case 0:
      {
        // Selling
        var dsSelling = ds_SellingFreightInfo_freight;
        if (dsSelling.getRowCount() > 0) {
          await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_011, ["House Selling"]); // @ 운임 자료가 존재 합니다. 삭제 후 적용 하세요.
        } else {
          await scwin.f_AirFreightTariff_freight("Selling"); //항공운임 aaf tariff 조회 

          if (ds_AirFreightTariff_freight.getRowCount() > 0) {
            rtnList = await scwin.f_AirFreightTariffCalc_freight("Selling");

            // 그리드 ROW 추가
            await scwin.f_FreightCodeInfo_freight("AAF", "");
            scwin.f_AddRow_freight("Selling");
            var rowS = dsSelling.getRowPosition() || 0;
            dsSelling.setCellData(rowS, "fareEngCd", ds_FcodeInfo_freight.getCellData(0, "col1"));
            dsSelling.setCellData(rowS, "fareEngNm", ds_FcodeInfo_freight.getCellData(0, "col2"));
            dsSelling.setCellData(rowS, "fareGrpCd", ds_FcodeInfo_freight.getCellData(0, "col6"));
            dsSelling.setCellData(rowS, "sellItemCd", ds_FcodeInfo_freight.getCellData(0, "col4"));
            dsSelling.setCellData(rowS, "vatYn", ds_FcodeInfo_freight.getCellData(0, "col8"));
            dsSelling.setCellData(rowS, "crcCd", "KRW");
            await scwin.f_CurrRateSetting_freight(rowS, "crcCd", "Selling");
            scwin.f_PkgWegihtSetting_freight(rowS, "fareEngCd", "Selling");
            if (dsSelling.getCellData(rowS, "chgWt") < rtnList[0]) {
              dsSelling.setCellData(rowS, "chgWt", rtnList[0]);
            }
            dsSelling.setCellData(rowS, "sellUpr", rtnList[1]);
            dsSelling.setCellData(rowS, "trfUpr", rtnList[1]);
            dsSelling.setCellData(rowS, "sellAmt", rtnList[2]);
            dsSelling.setCellData(rowS, "rateCls", rtnList[4]);
          }
          await scwin.f_AirOtherTariff_freight("Selling"); //항공 other tariff 조회

          if (ds_AirOtherTariff_freight.getRowCount() > 0) {
            await scwin.f_AirOtherTariffCalc_freight("Selling");
          }

          //Customer booking Cargo Pickup 자료 조회 해서 적용 
          var paramsS = {
            sysCd: "CoCommonEBC",
            queryId: "retrieveCoCargoPickupInfoDTOList",
            param1: "H",
            param2: scwin.hd_kcomcd,
            param3: ds_HouseFreightInfo_freight.getCellData(ds_HouseFreightInfo_freight.getRowPosition(), "blno")
          };
          let e = await scwin.execComboAndCopy(paramsS, {
            target: ds_AirCustBookingCargoPickupList_freight
          });
          if (e.responseJSON.resultDataSet[0].Code < 0) return;
          for (var j = 0; j < ds_AirCustBookingCargoPickupList_freight.getRowCount(); j++) {
            await scwin.f_AirTruckingTariff_freight(j, "Selling");
            if (ds_AirTruckingTariff_freight.getRowCount() >= 1) {
              await scwin.f_AirTruckingTariffCalc_freight(j, "Selling");
            }
          }
        }
        break;
      }
    default:
      break;
  }
};

