//-------------------------------------------------------------------------
// 금액 소숫점 처리
//-------------------------------------------------------------------------
scwin.f_TruncAmount_freight = function (gubun, amount) {
  var truncAmount = 0;
  switch (gubun) {
    case "1":
      // 소숫점 1자리 사사오입
      truncAmount = Math.round(amount);
      return truncAmount;
    case "2":
      // 소숫점 버림
      truncAmount = Math.round(amount - 0.5);
      return truncAmount;
    case "3":
      // 소숫점  버림 후 단자리 사사오입
      truncAmount = parseInt(Math.round(amount / 10) * 10, 10);
      return truncAmount;
    case "4":
      // 소숫점 버림 후 단자리 버림
      truncAmount = Math.round((amount - 5) / 10) * 10;
      return truncAmount;
    case "5":
      // 소숫점 1자리 사사오입 후 단자리 사사오입
      truncAmount = Math.round(Math.round(amount) / 10) * 10;
      return truncAmount;
    case "6":
      // 소숫점 1자리 사사오입 후 단자리 버림
      truncAmount = Math.round((Math.round(amount) - 5) / 10) * 10;
      return truncAmount;
    default:
      truncAmount = Math.round(amount);
      return truncAmount;
  }
};

