scwin.f_RetrieveTmp_freight = async function () {
  var outRec = "";
  if (ed_blnoTmp_freight.getValue() == "") {
    await $c.win.alert($p, "선조회할 BL번호가 없습니다");
    return false;
  }
  ds_tmpCnd_freight.set("blno", ed_blnoTmp_freight.getValue());
  if (scwin.tabIndex == 0) {
    //Selling
    outRec = "ds_SellingFreightInfo_freight";
    ds_tmpCnd_freight.set("rtrvTypCd", "SELLING");
    if (ds_SellingFreightInfo_freight.getTotalRow() > 0) {
      await $c.win.alert($p, "이미 매출이 등록된 건은 선조회 할 수 없습니다");
      return false;
    }
  } else if (scwin.tabIndex == 1) {
    //partner
    outRec = "ds_PartnerFreightInfo_freight";
    ds_tmpCnd_freight.set("rtrvTypCd", "PARTNER");
    if (ds_PartnerFreightInfo_freight.getTotalRow() > 0) {
      await $c.win.alert($p, "이미 PARTNER 실적이 등록된 건은 선조회 할 수 없습니다");
      return false;
    }
  } else if (scwin.tabIndex == 2) {
    //BUYING
    outRec = "ds_BuyingFreightInfo_freight";
    ds_tmpCnd_freight.set("rtrvTypCd", "BUYING");
    if (ds_BuyingFreightInfo_freight.getTotalRow() > 0) {
      await $c.win.alert($p, "이미 매입이 등록된 건은 선조회 할 수 없습니다");
      return false;
    }
  }
  sbm_RetrieveTmp_freight.ref = 'data:json,[{"id":"ds_tmpCnd_freight","key":"IN_DS1"},{"id":"' + outRec + '","key":"OUT_DS1"}]';
  sbm_RetrieveTmp_freight.target = 'data:json,{"id":"' + outRec + '","key":"OUT_DS1"}';
  $c.sbm.execute($p, sbm_RetrieveTmp_freight);
};

