scwin.sbm_Retrieve_freight_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return; // OnFail

  ds_HouseFreightInfo_freight.setRowPosition(0);
  ds_BuyingFreightInfo_freight.setRowPosition(0);
  ds_SellingFreightInfo_freight.setRowPosition(0);
  ds_PartnerFreightInfo_freight.setRowPosition(0);
  totalRowSelling.setValue(ds_SellingFreightInfo_freight.getTotalRow());
  totalRowPartner.setValue(ds_PartnerFreightInfo_freight.getTotalRow());
  totalRowBuying.setValue(ds_BuyingFreightInfo_freight.getTotalRow());
  scwin.ds_HouseFreightInfo_freight_OnLoadCompleted();
  for (var i = 0; i < ds_BuyingFreightInfo_freight.getTotalRow(); i++) {
    scwin.setRowNumSeq(ds_BuyingFreightInfo_freight, i);
    ds_BuyingFreightInfo_freight.modifyRowStatus(i, "R");
  }
  for (var i = 0; i < ds_SellingFreightInfo_freight.getTotalRow(); i++) {
    scwin.setRowNumSeq(ds_SellingFreightInfo_freight, i);
    ds_SellingFreightInfo_freight.modifyRowStatus(i, "R");
  }
  for (var i = 0; i < ds_PartnerFreightInfo_freight.getTotalRow(); i++) {
    scwin.setRowNumSeq(ds_PartnerFreightInfo_freight, i);
    ds_PartnerFreightInfo_freight.modifyRowStatus(i, "R");
  }
  if (ds_HouseFreightInfo_freight.getRowCount() == 0) {
    await scwin.f_ProcessResult_freight("None");
  } else {
    await scwin.f_ProcessResult_freight("FreightInfo");
  }
  if (scwin.v_linkcheck == 9 || scwin.v_linkcheck == "9") {
    scwin.f_Set_freight("UPDATE");
    var rowCnt = parseInt(scwin.p_row_cnt || 0);
    var data = scwin.p_data || "";
    var rtnValues = data.split("$");
    for (var t = 0; t <= rowCnt - 1; t++) {
      rtnValues[t] = rtnValues[t].split("_");
    }
    var k = ds_BuyingFreightInfo_freight.getRowCount();
    if (!rtnValues || rtnValues.length == 0) {
      return false;
    }
    for (var i = 0; i < rtnValues.length; i++) {
      scwin.f_AddRow_freight("Buying");
      ds_frt_condition_freight.set("fromCd", rtnValues[i][2]);
      var e = await $c.sbm.execute($p, sbm_retrieve_frtMapping_freight);
      if (e.responseJSON.resultDataSet[0].Code < 0) return;
      var row = ds_BuyingFreightInfo_freight.getRowPosition() || 0;
      ds_BuyingFreightInfo_freight.setCellData(row, "fareEngCd", ds_frtMapping_freight.getCellData(0, "toCd"));
      ds_BuyingFreightInfo_freight.setCellData(row, "fareEngNm", ds_frtMapping_freight.getCellData(0, "description"));
      ds_BuyingFreightInfo_freight.setCellData(row, "selpchItemCd", ds_frtMapping_freight.getCellData(0, "dtlCd1"));
      ds_BuyingFreightInfo_freight.setCellData(row, "fareGrpCd", ds_frtMapping_freight.getCellData(0, "dtlCd2"));
      ds_BuyingFreightInfo_freight.setCellData(row, "vatYn", ds_frtMapping_freight.getCellData(0, "dtlCd3"));
      var vatYn = ds_BuyingFreightInfo_freight.getCellData(row, "vatYn");
      if (vatYn != 0 && vatYn != "0" && vatYn != "") {
        var vat = Math.round(parseFloat(rtnValues[i][6] || 0) * 0.1 - 0.5);
        ds_BuyingFreightInfo_freight.setCellData(row, "vat", vat);
      }
      gr_BuyingFreightInfo_freight.focus();
      gr_BuyingFreightInfo_freight.setFocusedCell(row, "pchsTyp");
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsClntNo", rtnValues[i][0]);
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsClntNm", rtnValues[i][1]);
      ds_BuyingFreightInfo_freight.setCellData(row, "fareEngCd", rtnValues[i][2]);
      ds_BuyingFreightInfo_freight.setCellData(row, "crcCd", rtnValues[i][3]);
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmtFcrc", rtnValues[i][4]);
      ds_BuyingFreightInfo_freight.setCellData(row, "exRate", rtnValues[i][5]);
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmt", rtnValues[i][6]);
      ds_BuyingFreightInfo_freight.setCellData(row, "chgWt", rtnValues[i][7]);
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsUpr", rtnValues[i][8]);
      ds_BuyingFreightInfo_freight.modifyRowStatus(row, "U");
    }
    tab_main.setSelectedTabIndex(2);
  }
  var exIdx = lc_exgb_freight.getSelectedIndex();
  if (exIdx == 0) {
    scwin.tabIndex = 2;
  } else if (exIdx == 1) {
    scwin.tabIndex = 1;
  } else if (exIdx == 2) {
    scwin.tabIndex = 0;
  }
};
