// grid edit helpers
scwin._gridEditOld = {
  gridId: "",
  row: -1,
  colId: "",
  value: ""
};
scwin._captureGridOld = function (gridId, ds, rowIndex, columnIndex, grid) {
  var colId = grid.getFocusedColumnID();
  scwin._gridEditOld = {
    gridId: gridId,
    row: rowIndex,
    colId: colId,
    value: ds.getCellData(rowIndex, colId)
  };
};
scwin._getGridOldValue = function (gridId, rowIndex, colId) {
  if (scwin._gridEditOld.gridId == gridId && scwin._gridEditOld.row == rowIndex && scwin._gridEditOld.colId == colId) {
    return scwin._gridEditOld.value;
  }
  return "";
};

// rowStatus 기준으로 삭제 방식 분기
scwin._deleteRow = function (ds, rowIndex) {
  if (!ds || rowIndex == null || rowIndex < 0) return;
  var st = typeof ds.getRowStatus === "function" ? ds.getRowStatus(rowIndex) : null;
  if (st === "C") {
    ds.removeRow(rowIndex);
  } else {
    ds.deleteRow(rowIndex);
  }
};

