// grid: SellingFreightInfo_freight
// for=gr_SellingFreightInfo_freight event=OnCloseUp(Row,Colid)
scwin.gr_SellingFreightInfo_freight_onafteredit = async function (row, columnIndex, value) {
  var colId = gr_SellingFreightInfo_freight.getFocusedColumnID();
  var oldValue = scwin._getGridOldValue("gr_SellingFreightInfo_freight", row, colId);
  switch (colId) {
    case "crcCd":
      await scwin.f_CurrRateSetting_freight(row, colId, "Selling"); // 화율정보에 따른 EX-Rate 가져오기
      if (value != "KRW") {
        gr_SellingFreightInfo_freight.setCellReadOnly(row, "sellAmtFcrc", false);
      } else if (value == "KRW") {
        gr_SellingFreightInfo_freight.setCellReadOnly(row, "sellAmtFcrc", true);
      }
      break;
    case "bilgClntNo":
      if (value != "" && value != oldValue) {
        ds_SellingFreightInfo_freight.setCellData(row, "bilgClntNm", "");
        ds_SellingFreightInfo_freight.setCellData(row, "bilgClntNo", value);
        scwin.popupOpen = true;
        await scwin.f_PopUpGrid_freight("SellingCustomer", row, "T", "F", "F");
      } else if (value == "") {
        ds_SellingFreightInfo_freight.setCellData(row, "bilgClntNm", "");
        ds_SellingFreightInfo_freight.setCellData(row, "bilgClntNo", "");
      }
      break;
    case "fareEngCd":
      if (value != "" && value != oldValue) {
        ds_SellingFreightInfo_freight.setCellData(row, "fareEngNm", "");
        ds_SellingFreightInfo_freight.setCellData(row, "fareEngCd", value);
        scwin.popupOpen = true;
        await scwin.f_PopUpGrid_freight("SellingFreight", row, "T", "F", "F");
      } else if (value == "") {
        ds_SellingFreightInfo_freight.setCellData(row, "fareEngNm", "");
        ds_SellingFreightInfo_freight.setCellData(row, "fareEngCd", "");
      }
      break;
  }
  if (colId == "crcCd") {
    ds_SellingFreightInfo_freight.setCellData(row, colId, value);
    await scwin.f_CurrRateSetting_freight(row, colId, "Selling");
  }
  if (value != oldValue) {
    scwin.f_PkgWegihtSetting_freight(row, colId, "Selling");
    if (colId == "fareEngCd") {
      var fareEngCd = value; //ds_SellingFreightInfo_freight.getCellData(row, "fareEngCd");
      if (fareEngCd == "ATC" || fareEngCd == "ATCV") {
        ds_SellingFreightInfo_freight.setCellData(row, "crcCd", "KRW");
        ds_SellingFreightInfo_freight.setCellData(row, "exRate", 1);
        ds_SellingFreightInfo_freight.setCellData(row, "sellUpr", 1);
        ds_SellingFreightInfo_freight.setCellData(row, "grossWt", ds_HouseFreightInfo_freight.getCellData(ds_HouseFreightInfo_freight.getRowPosition(), "mftwht"));
        var grossWt = parseFloat(ds_SellingFreightInfo_freight.getCellData(row, "grossWt") || 0);
        ds_SellingFreightInfo_freight.setCellData(row, "sellAmt", Math.round(grossWt * 35 + 2000 - 0.5));
        if (fareEngCd == "ATCV") {
          var pchsAmt = parseFloat(ds_SellingFreightInfo_freight.getCellData(row, "pchsAmt") || 0);
          ds_SellingFreightInfo_freight.setCellData(row, "vat", Math.round(pchsAmt * 0.1));
        }
      } else if (fareEngCd == "ADO" || fareEngCd == "ADOV" || fareEngCd == "APUV" || fareEngCd == "ALO" || fareEngCd == "AIT" || fareEngCd == "AHC" || fareEngCd == "AHCV" || fareEngCd == "APH" || fareEngCd == "CHC" || fareEngCd == "MHC" || fareEngCd == "ADL" || fareEngCd == "ADLC" || fareEngCd == "ADLV" || fareEngCd == "ADLZ" || fareEngCd == "AFD" || fareEngCd == "ASA" || fareEngCd == "CDLV" || fareEngCd == "INP" || fareEngCd == "ADL1" || fareEngCd == "DTY" || fareEngCd == "ACL" || fareEngCd == "ACLV" || fareEngCd == "AFC" || fareEngCd == "AOC" || fareEngCd == "AOCV" || fareEngCd == "BTC" || fareEngCd == "BTCV" || fareEngCd == "BTF" || fareEngCd == "BTFV" || fareEngCd == "AHCJ" || fareEngCd == "AOCJ" || fareEngCd == "AHCK" || fareEngCd == "AOCK") {
        ds_SellingFreightInfo_freight.setCellData(row, "fareUnit", "P");
        ds_SellingFreightInfo_freight.setCellData(row, "qty", "1");
      }
    }
    scwin.f_RateAmount_freight(row, colId, "Selling", oldValue);
  }
  gr_SellingFreightInfo_freight.focus();
};
scwin.gr_SellingFreightInfo_freight_onbeforeedit = async function (rowIndex, columnIndex, value) {
  scwin._captureGridOld("gr_SellingFreightInfo_freight", ds_SellingFreightInfo_freight, rowIndex, columnIndex, gr_SellingFreightInfo_freight);
};

