scwin.gr_BuyingFreightInfo_freight_onafteredit = async function (rowIndex, columnIndex, value) {
  var Colid = gr_BuyingFreightInfo_freight.getFocusedColumnID();
  switch (Colid) {
    case "pchsTyp":
      if (ds_BuyingFreightInfo_freight.getCellData(rowIndex, "pchsTyp") == "3") {
        gr_BuyingFreightInfo_freight.setColumnReadOnly("sellDeptCd", false);
      } else {
        gr_BuyingFreightInfo_freight.setColumnReadOnly("sellDeptCd", true);
      }
      break;
    case "crcCd":
      await scwin.f_CurrRateSetting_freight(rowIndex, Colid, "Buying"); // 화율정보에 따른 EX-Rate 가져오기
      if (value != "KRW") {
        gr_BuyingFreightInfo_freight.setCellReadOnly(rowIndex, "pchsAmtFcrc", false);
      } else if (value == "KRW") {
        gr_BuyingFreightInfo_freight.setCellReadOnly(rowIndex, "pchsAmtFcrc", true);
      }
      break;
    case "pchsClntNo":
    case "fareEngCd":
    case "sellDeptCd":
      scwin.gr_BuyingFreightInfo_freight_OnExit(rowIndex, columnIndex, value);
      break;
    default:
      scwin.gr_BuyingFreightInfo_freight_OnExit(rowIndex, columnIndex, value);
      break;
  }
  gr_BuyingFreightInfo_freight.focus();
};

// for=gr_BuyingFreightInfo_freight event=OnExit(row,colid,olddata)
scwin.gr_BuyingFreightInfo_freight_OnExit = async function (rowIndex, columnIndex, value) {
  var row = rowIndex;
  var colId = gr_BuyingFreightInfo_freight.getFocusedColumnID();
  var oldValue = scwin._getGridOldValue("ds_BuyingFreightInfo_freight", row, colId);
  switch (colId) {
    case "pchsClntNo":
      if (value != "" && value != oldValue) {
        ds_BuyingFreightInfo_freight.setCellData(row, "pchsClntNm", "");
        ds_BuyingFreightInfo_freight.setCellData(row, "pchsClntNo", value);
        scwin.popupOpen = true;
        await scwin.f_PopUpGrid_freight("BuyingCustomer", row, "T", "F", "F");
      } else if (value == "") {
        ds_BuyingFreightInfo_freight.setCellData(row, "pchsClntNm", "");
        ds_BuyingFreightInfo_freight.setCellData(row, "pchsClntNo", "");
      }
      break;
    case "fareEngCd":
      if (value != "" && value != oldValue) {
        ds_BuyingFreightInfo_freight.setCellData(row, "fareEngNm", "");
        ds_BuyingFreightInfo_freight.setCellData(row, "fareEngCd", value);
        scwin.popupOpen = true;
        await scwin.f_PopUpGrid_freight("BuyingFreight", row, "T", "F", "F");
      } else if (value == "") {
        ds_BuyingFreightInfo_freight.setCellData(row, "fareEngNm", "");
        ds_BuyingFreightInfo_freight.setCellData(row, "fareEngCd", "");
      }
      break;
    case "sellDeptCd":
      if (value != "" && value != oldValue) {
        ds_BuyingFreightInfo_freight.setCellData(row, "sellDeptCd", value);
        ds_BuyingFreightInfo_freight.setCellData(row, "sellDeptNm", "");
        scwin.popupOpen = true;
        await scwin.f_PopUpGrid_freight("BuyingInnerDept", row, "T", "F", "F");
      } else if (value == "") {
        ds_BuyingFreightInfo_freight.setCellData(row, "sellDeptNm", "");
        ds_BuyingFreightInfo_freight.setCellData(row, "sellDeptCd", "");
      }
      break;
    default:
      break;
  }
  if (colId == "crcCd") {
    ds_BuyingFreightInfo_freight.setCellData(row, colId, value);
    await scwin.f_CurrRateSetting_freight(row, colId, "Buying");
  }
  if (value != oldValue) {
    // ds_BuyingFreightInfo_freight.setCellData(row, colId, value);
    scwin.f_PkgWegihtSetting_freight(row, colId, "Buying");
    if (colId == "fareEngCd") {
      var fareEngCd = value; //ds_BuyingFreightInfo_freight.getCellData(row, "fareEngCd");
      if (fareEngCd == "ATC" || fareEngCd == "ATCV") {
        ds_BuyingFreightInfo_freight.setCellData(row, "crcCd", "KRW");
        ds_BuyingFreightInfo_freight.setCellData(row, "exRate", 1);
        ds_BuyingFreightInfo_freight.setCellData(row, "pchsUpr", 1);
        ds_BuyingFreightInfo_freight.setCellData(row, "chgWt", ds_HouseFreightInfo_freight.getCellData(ds_HouseFreightInfo_freight.getRowPosition(), "mftwht"));
        var chgWt = parseFloat(ds_BuyingFreightInfo_freight.getCellData(row, "chgWt") || 0);
        ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmt", Math.round(chgWt * 35 + 2000 - 0.5));
        if (fareEngCd == "ATCV") {
          var pchsAmt2 = parseFloat(ds_BuyingFreightInfo_freight.getCellData(row, "pchsAmt") || 0);
          ds_BuyingFreightInfo_freight.setCellData(row, "vat", Math.round(pchsAmt2 * 0.1 - 0.5));
        }
      } else if (fareEngCd == "ADO" || fareEngCd == "ADOV" || fareEngCd == "APUV" || fareEngCd == "ALO" || fareEngCd == "AIT" || fareEngCd == "AHC" || fareEngCd == "AHCV" || fareEngCd == "APH" || fareEngCd == "CHC" || fareEngCd == "MHC" || fareEngCd == "ADL" || fareEngCd == "ADLC" || fareEngCd == "ADLV" || fareEngCd == "ADLZ" || fareEngCd == "AFD" || fareEngCd == "ASA" || fareEngCd == "CDLV" || fareEngCd == "INP" || fareEngCd == "ADL1" || fareEngCd == "DTY" || fareEngCd == "ACL" || fareEngCd == "ACLV" || fareEngCd == "AFC" || fareEngCd == "AOC" || fareEngCd == "AOCV" || fareEngCd == "BTC" || fareEngCd == "BTCV" || fareEngCd == "BTF" || fareEngCd == "BTFV" || fareEngCd == "AHCJ" || fareEngCd == "AOCJ" || fareEngCd == "AHCK" || fareEngCd == "AOCK") {
        ds_BuyingFreightInfo_freight.setCellData(row, "fareUnit", "P");
        ds_BuyingFreightInfo_freight.setCellData(row, "qty", "1");
      }
    }
    scwin.f_RateAmount_freight(row, colId, "Buying", oldValue);
  }
};

