// for=ds_SellingFreightInfo_freight event=onColumnChanged(row,colid)
scwin.ds_SellingFreightInfo_freight_oncelldatachange = function (info) {
  var colid = info.colID;
  var row = info.rowIndex;
  switch (colid) {
    case "chgWt":
      scwin.f_GridChangeValidate_freight(ds_SellingFreightInfo_freight, row, colid);
      break;
    case "prtnAmt":
      break;
    case "fareUnit":
      if (ds_SellingFreightInfo_freight.getCellData(row, colid) == "P") {
        //case
        ds_SellingFreightInfo_freight.setCellData(row, "qty", 1);
        ds_SellingFreightInfo_freight.setCellData(row, "chgWt", 0);
        ds_SellingFreightInfo_freight.setCellData(row, "grossWt", 0);
      } else if (ds_SellingFreightInfo_freight.getCellData(row, colid) == "C") {
        //c/wt
        ds_SellingFreightInfo_freight.setCellData(row, "qty", ds_HouseBillInfo.getCellData(0, "tcwht"));
        ds_SellingFreightInfo_freight.setCellData(row, "chgWt", ds_HouseBillInfo.getCellData(0, "tcwht"));
        ds_SellingFreightInfo_freight.setCellData(row, "grossWt", 0);
      } else if (ds_SellingFreightInfo_freight.getCellData(row, colid) == "G") {
        //g/wt
        ds_SellingFreightInfo_freight.setCellData(row, "grossWt", ds_SellingFreightInfo_freight.getCellData(row, "qty"));
        ds_SellingFreightInfo_freight.setCellData(row, "chgWt", 0);
      }
      break;
    case "qty":
      if (ds_SellingFreightInfo_freight.getCellData(row, "fareUnit") == "P") {
        //case
        ds_SellingFreightInfo_freight.setCellData(row, "chgWt", 0);
        ds_SellingFreightInfo_freight.setCellData(row, "grossWt", 0);
      } else if (ds_SellingFreightInfo_freight.getCellData(row, "fareUnit") == "C") {
        //c/wt
        ds_SellingFreightInfo_freight.setCellData(row, "qty", ds_HouseBillInfo.getCellData(0, "tcwht"));
        ds_SellingFreightInfo_freight.setCellData(row, "chgWt", ds_HouseBillInfo.getCellData(0, "tcwht"));
        ds_SellingFreightInfo_freight.setCellData(row, "grossWt", 0);
      } else if (ds_SellingFreightInfo_freight.getCellData(row, "fareUnit") == "G") {
        //g/wt
        ds_SellingFreightInfo_freight.setCellData(row, "grossWt", ds_SellingFreightInfo_freight.getCellData(row, "qty"));
        ds_SellingFreightInfo_freight.setCellData(row, "chgWt", 0);
      }
      break;
    default:
      break;
  }
  scwin.f_pcSummery_freight();
  scwin.f_TotalCac_freight("Selling");
};

